import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { LandPrice2026 } from '../../types';
import { Search, Plus, Edit2, Trash2, X, Save, Coins, MapPin, Landmark, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { formatCurrency } from '../../utils/helpers';

const LandPrice2026Manager: React.FC = () => {
    const [data, setData] = useState<LandPrice2026[]>([]);
    const [loading, setLoading] = useState(false);
    const [searchFilters, setSearchFilters] = useState({ phuongxa: '', tenduong: '' });
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [formData, setFormData] = useState<any>({});
    const [editingId, setEditingId] = useState<number | null>(null);

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const results = await adminService.searchLandPrices2026(searchFilters.phuongxa, searchFilters.tenduong);
            setData(results);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        if (!formData.phuongxa || !formData.tenduong || !formData.dato) {
            alert("Vui lòng nhập đầy đủ các trường bắt buộc (*)");
            return;
        }

        setLoading(true);
        try {
            if (editingId) {
                await adminService.updateLandPrice2026(editingId, formData);
            } else {
                await adminService.addLandPrice2026(formData);
            }
            setIsModalOpen(false);
            loadData();
        } catch (e: any) {
            alert("Lỗi: " + e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: number, name: string) => {
        if (confirm(`Xóa dòng giá đất tại đường ${name}?`)) {
            try {
                await adminService.deleteLandPrice2026(id);
                loadData();
            } catch (e: any) {
                alert(e.message);
            }
        }
    };

    const openEdit = (item: LandPrice2026) => {
        setEditingId(item.id);
        setFormData({ ...item });
        setIsModalOpen(true);
    };

    const openAdd = () => {
        setEditingId(null);
        setFormData({
            phuongxa: '', tenduong: '', tinhcu: 'TP.HCM', 
            tu: '', den: '', dato: 0, dattmdv: 0, datsxkdpnn: 0,
            nam_ap_dung: 2026
