                        placeholder="Tìm theo khu vực..."
                        value={searchFilters.phuongxa}
                        onChange={e => setSearchFilters({...searchFilters, phuongxa: e.target.value})}
                    />
                </div>
                <div className="flex-1 min-w-[200px] space-y-1.5">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Tên đường</label>
                    <input 
                        className="w-full bg-gray-900 border border-gray-700 rounded-lg px-3 py-2 text-xs outline-none focus:border-blue-500" 
                        placeholder="Tìm theo tên đường..."
                        value={searchFilters.tenduong}
                        onChange={e => setSearchFilters({...searchFilters, tenduong: e.target.value})}
                    />
                </div>
                <button 
                    onClick={loadData}
                    className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2 rounded-lg text-xs font-black uppercase flex items-center gap-2 shadow-lg transition-all"
                >
                    <Search size={16}/> Lọc dữ liệu
                </button>
                <button 
