import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng và SRID (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tìm tên cột và SRID hiện tại của bảng
     */
    const resolveTableColumns = async (tableName) => {
        if (SCHEMA_CACHE.has(tableName)) {
            return SCHEMA_CACHE.get(tableName);
        }

        try {
            // Lấy danh sách cột
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            // Lấy SRID hiện tại của cột geometry
            const sridRes = await pool.query(`
                SELECT srid FROM geometry_columns 
                WHERE f_table_name = $1 AND f_geometry_column = 'geometry'
                LIMIT 1
            `, [tableName]);

            const currentSrid = sridRes.rows[0]?.srid || 4326;

            const dbColsMap = {};
            res.rows.forEach(r => {
                dbColsMap[r.column_name.toLowerCase()] = r.column_name;
            });

            const mapping = { _srid: currentSrid };
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) {
                    if (dbColsMap[candidate]) {
                        foundCol = dbColsMap[candidate];
                        break;
                    }
                }
                mapping[standardKey] = foundCol;
            }

            SCHEMA_CACHE.set(tableName, mapping);
            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich', _srid: 4326 };
        }
    };

    const syncTableSchema = async (tableName) => {
        try {
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            // 1. Kiểm tra thiếu cột thuộc tính
            const missingCols = [];
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });

            if (missingCols.length > 0) {
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
            }

            // 2. Tự động sửa SRID 4326 -> 9210 nếu cần
            if (currentMap._srid !== 9210) {
                try {
                    await pool.query(`
                        ALTER TABLE "${tableName}" 
                        ALTER COLUMN geometry TYPE geometry(Geometry, 9210) 
                        USING ST_SetSRID(geometry, 9210)
                    `);
                    console.log(`[Migrate] Forced SRID 9210 for table: ${tableName}`);
                } catch (err) {
                    console.warn(`[Migrate Skip] Could not force SRID 9210 for ${tableName}, using dynamic SRID instead.`);
                }
            }

            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
            SCHEMA_CACHE.delete(tableName); 
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 9210),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/rename', async (req, res) => {
        const { oldName, newName, displayName, description } = req.body;
        try {
            await pool.query('BEGIN');
            // Nếu tên bảng vật lý thay đổi, thực hiện ALTER TABLE
            if (oldName !== newName) {
                await pool.query(`ALTER TABLE "${oldName}" RENAME TO "${newName}"`);
            }
            // Cập nhật Registry
            await pool.query(`
                UPDATE spatial_tables_registry 
                SET table_name = $1, display_name = $2, description = $3 
                WHERE table_name = $4
            `, [newName, displayName, description, oldName]);

            await pool.query('COMMIT');
            SCHEMA_CACHE.delete(oldName);
            SCHEMA_CACHE.delete(newName);
            res.json({ status: 'ok' });
        } catch (e) {
            await pool.query('ROLLBACK');
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        const { tableName } = req.body;
        try {
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            SCHEMA_CACHE.delete(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        try {
            const cols = await resolveTableColumns(table);
            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;
            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            if (tenchu) { query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; params.push(`%${tenchu}%`); }
            if (diachi) { query += ` AND "${cols.diachi}" ILIKE $${idx++}`; params.push(`%${diachi}%`); }
            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            res.json(result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null
            })));
        } catch (e) {
            SCHEMA_CACHE.delete(table);
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
            }
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    /**
     * Endpoint NẠP HÀNG LOẠT (BULK INSERT)
     */
    router.post('/data/:table/bulk', async (req, res) => {
        const { table } = req.params;
        const { items } = req.body; // Mảng các thửa đất [{sodoto, sothua, ...}]
        if (!Array.isArray(items) || items.length === 0) return res.status(400).json({ error: "Dữ liệu không hợp lệ." });

        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            await pool.query('BEGIN');

            for (const item of items) {
                let geomSql = 'NULL';
                const params = [item.sodoto, item.sothua, item.tenchu, item.diachi, item.loaidat, item.dientich];
                if (item.geometry) {
                    geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                    params.push(JSON.stringify(item.geometry));
                }
                const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql})`;
                await pool.query(query, params);
            }

            await pool.query('COMMIT');
            await logSystemAction(req, 'BULK_IMPORT', `Nạp hàng loạt ${items.length} thửa đất vào bảng ${table}`);
            res.json({ status: 'ok', count: items.length });
        } catch (e) {
            await pool.query('ROLLBACK');
            res.status(500).json({ error: e.message });
        }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($${idx}), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 
        if (!file) return res.status(400).json({ error: 'No file uploaded' });
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;
            const buffer = fs.readFileSync(file.path);
            let geojson;
            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());
            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;
            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");

            if (gid) {
                await pool.query(`UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})) WHERE gid=$8`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]);
            } else {
                await pool.query(`INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})))`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]);
            }
            fs.unlinkSync(file.path);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import { LandParcel } from '../types';

const getApiUrl = () => {
    const { hostname, protocol } = window.location;
    const isLocal = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocal) {
        return `${protocol}//${hostname}:3004`;
    }
    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

export interface ParcelDTO {
    gid?: number; 
    sothua: string;
    sodoto: string;
    tenchu?: string;
    diachi?: string;
    loaidat?: string; 
    dientich?: number;
    geometry?: any; 
    file?: File | null; 
    [key: string]: any; 
}

export interface SpatialTable {
    table_name: string;
    display_name: string;
    description?: string;
}

const getAuthHeaders = () => {
    const headers: any = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const handleResponse = async (res: Response) => {
    const responseText = await res.text();
    let responseData: any = null;
    if (responseText) {
        try { responseData = JSON.parse(responseText); } catch (e) {}
    }
    if (!res.ok) {
        let message = `Lỗi API (${res.status})`;
        if (responseData && (responseData.error || responseData.message)) {
            message = responseData.error || responseData.message;
        }
        throw new Error(message);
    }
    return responseData || { status: 'ok' };
};

export const parcelApi = {
    getAll: async (layer: string, filters?: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }) => {
        let queryString = `?t=${Date.now()}`;
        if (filters) {
            if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
            if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
            if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
            if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
        }
        const res = await fetch(`${API_URL}/api/data/${layer}${queryString}`, { headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    getExtent: async (layer: string) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/extent`, { headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    create: async (layer: string, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}`, { method: 'POST', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    bulkCreate: async (layer: string, items: ParcelDTO[]) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/bulk`, { 
            method: 'POST', 
            headers: { ...getAuthHeaders() }, 
            body: JSON.stringify({ items }) 
        });
        return await handleResponse(res);
    },

    createWithUpload: async (layer: string, data: ParcelDTO) => {
        const formData = new FormData();
        Object.keys(data).forEach(key => {
            if (key === 'file' && data[key]) formData.append('file', data[key] as File);
            else if (data[key] !== undefined && data[key] !== null) formData.append(key, String(data[key]));
        });
        const headers = { ...getAuthHeaders() };
        delete headers['Content-Type'];
        const res = await fetch(`${API_URL}/api/data/${layer}/upload`, { method: 'POST', headers, body: formData });
        return await handleResponse(res);
    },

    update: async (layer: string, gid: number, data: ParcelDTO) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify(data) });
        return await handleResponse(res);
    },

    updateGeometry: async (layer: string, gid: number, geometry: any, area: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}/geometry`, { method: 'PUT', headers: { ...getAuthHeaders() }, body: JSON.stringify({ geometry, area }) });
        return await handleResponse(res);
    },

    delete: async (layer: string, gid: number) => {
        const res = await fetch(`${API_URL}/api/data/${layer}/${gid}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
        return await handleResponse(res);
    },

    manageTables: {
        getAll: async (): Promise<SpatialTable[]> => {
            const res = await fetch(`${API_URL}/api/spatial-tables?t=${Date.now()}`, { headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        },
        create: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        link: async (tableName: string, displayName?: string, description?: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/link`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ tableName: name, displayName, description })
            });
            return await handleResponse(res);
        },
        rename: async (oldName: string, newName: string, displayName: string, description?: string) => {
            const res = await fetch(`${API_URL}/api/spatial-tables/rename`, {
                method: 'POST',
                headers: { ...getAuthHeaders() },
                body: JSON.stringify({ 
                    oldName: oldName.toLowerCase().trim(), 
                    newName: newName.toLowerCase().trim(), 
                    displayName, 
                    description 
                })
            });
            return await handleResponse(res);
        },
        unlink: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/unlink`, { 
                method: 'POST', 
                headers: { ...getAuthHeaders() }, 
                body: JSON.stringify({ tableName: name }) 
            });
            return await handleResponse(res);
        },
        delete: async (tableName: string) => {
            const name = (tableName || '').toLowerCase().trim();
            const res = await fetch(`${API_URL}/api/spatial-tables/${name}`, { method: 'DELETE', headers: { ...getAuthHeaders() } });
            return await handleResponse(res);
        }
    }
};

import React, { useState, useRef } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2 } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParcelDTO[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParcelDTO[] = features.map((f: any) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const handleImport = async () => {
        if (parsedData.length === 0) return;
        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-6xl shadow-2xl flex flex-col max-h-[90vh]">
                <div className="p-6 border-b border-gray-800 flex justify-between items-center bg-gray-950/50">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-3 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={28} />
                        </div>
                        <div>
                            <h3 className="text-xl font-black uppercase text-white leading-none mb-1">Nhập tệp dữ liệu hàng loạt</h3>
                            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> Đích: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={28}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
                    {/* Panel trái: File upload & Stats */}
                    <div className="w-full md:w-80 border-r border-gray-800 p-8 space-y-8 bg-gray-950/20">
                        <div 
                            className={`p-6 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex flex-col items-center gap-4 text-center ${file ? 'border-emerald-500/50 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-900/50'}`}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className={`p-4 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                <FileUp size={32}/>
                            </div>
                            <div>
                                <p className="text-xs font-black text-white uppercase mb-1">{file ? "Thay đổi file" : "Chọn file dữ liệu"}</p>
                                <p className="text-[9px] text-gray-500 font-bold uppercase">ZIP (SHP) hoặc GeoJSON</p>
                            </div>
                            <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                        </div>

                        {parsedData.length > 0 && (
                            <div className="space-y-4 animate-in slide-in-from-left-4 duration-500">
                                <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest border-l-2 border-indigo-500 pl-3">Thống kê dữ liệu</h4>
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Số thửa</p>
                                        <p className="text-xl font-black text-white">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Hợp lệ</p>
                                        <p className="text-xl font-black text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                                <div className="bg-indigo-900/10 border border-indigo-500/20 p-4 rounded-2xl flex items-start gap-3">
                                    <Info className="text-indigo-400 shrink-0" size={16}/>
                                    <p className="text-[9px] text-indigo-300 font-bold uppercase leading-relaxed">Hệ thống sẽ tự động map các trường dữ liệu và tính toán diện tích Geodesic.</p>
                                </div>
                            </div>
                        )}

                        {error && (
                            <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3">
                                <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                <p className="text-xs text-red-400 font-bold leading-tight">{error}</p>
                            </div>
                        )}
                    </div>

                    {/* Panel phải: Preview table */}
                    <div className="flex-1 bg-gray-900/50 overflow-hidden flex flex-col">
                        {isParsing ? (
                            <div className="flex-1 flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-indigo-500" size={48} />
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Đang phân tích cấu trúc file...</p>
                            </div>
                        ) : parsedData.length > 0 ? (
                            <div className="flex-1 flex flex-col overflow-hidden">
                                <div className="flex-1 overflow-auto custom-scrollbar">
                                    <table className="w-full text-xs text-left">
                                        <thead className="bg-gray-950 text-gray-500 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                            <tr>
                                                <th className="p-4 w-12 text-center">STT</th>
                                                <th className="p-4">Số tờ/thửa</th>
                                                <th className="p-4">Chủ sử dụng</th>
                                                <th className="p-4">Mục đích</th>
                                                <th className="p-4 text-right">Diện tích (m²)</th>
                                                <th className="p-4 w-12"></th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-800">
                                            {parsedData.map((p, i) => (
                                                <tr key={i} className="hover:bg-indigo-600/5 transition-colors">
                                                    <td className="p-4 text-center text-gray-600 font-mono">{i + 1}</td>
                                                    <td className="p-4">
                                                        <span className={`font-black ${(!p.sodoto || !p.sothua) ? 'text-red-500' : 'text-blue-400'}`}>
                                                            {p.sodoto || '?'}/{p.sothua || '?'}
                                                        </span>
                                                    </td>
                                                    <td className="p-4 text-gray-300 truncate max-w-[150px]">{p.tenchu || '--'}</td>
                                                    <td className="p-4"><span className="bg-gray-800 px-2 py-0.5 rounded text-[9px] font-black border border-gray-700">{p.loaidat || '--'}</span></td>
                                                    <td className="p-4 text-right font-mono font-bold text-emerald-500">{p.dientich.toLocaleString()}</td>
                                                    <td className="p-4">
                                                        <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="text-gray-600 hover:text-red-500 transition-colors">
                                                            <Trash2 size={14}/>
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                                <div className="p-6 bg-gray-950 border-t border-gray-800 flex justify-between items-center">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Tổng cộng <span className="text-white">{parsedData.length}</span> thửa đất sẵn sàng nạp.
                                    </p>
                                    <div className="flex gap-3">
                                        <button onClick={onClose} className="px-6 py-3 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DỮ LIỆU
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center opacity-10 gap-6">
                                <Database size={120} />
                                <p className="text-xl font-black uppercase tracking-[0.4em]">Preview Area</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useEffect, useState, useCallback } from 'react';
import { parcelApi, ParcelDTO, SpatialTable } from '../services/parcelApi';
import { RefreshCw, Database, Layers, CheckCircle2, AlertTriangle, Info, Plus, FileSpreadsheet } from 'lucide-react';

// Sub-components
import TableFilter from '../components/admin/parcel/TableFilter';
import ParcelList from '../components/admin/parcel/ParcelList';
import QuickView from '../components/admin/parcel/QuickView';
import ParcelForm from '../components/admin/parcel/ParcelForm';
import BulkImportModal from '../components/admin/parcel/BulkImportModal';

const ParcelManager: React.FC = () => {
    const [layer, setLayer] = useState('');
    const [availableTables, setAvailableTables] = useState<SpatialTable[]>([]);
    const [parcels, setParcels] = useState<ParcelDTO[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [hasSearched, setHasSearched] = useState(false);
    const [searchFilters, setSearchFilters] = useState({ sodoto: '', sothua: '', tenchu: '', diachi: '' });

    // Modal Management
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [isBulkOpen, setIsBulkOpen] = useState(false);
    const [isPreviewOpen, setIsPreviewOpen] = useState(false);
    const [editingId, setEditingId] = useState<number | null>(null);
    const [selectedItem, setSelectedItem] = useState<any>(null);
    const [formData, setFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });

    // System Dialog
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'alert' | 'confirm' | 'success' | 'error'; title: string; message: string; onConfirm?: () => void; }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    // --- LOGIC: FETCHING ---
    const loadTables = async () => {
        setLoading(true);
        try {
            const tables = await parcelApi.manageTables.getAll();
            setAvailableTables(tables);
            if (tables.length > 0 && !layer) setLayer(tables[0].table_name);
            setError(null);
        } catch (e: any) { setError("Không thể tải danh sách lớp dữ liệu."); }
        finally { setLoading(false); }
    };

    useEffect(() => { loadTables(); }, []);
    useEffect(() => { if (layer) { setParcels([]); setHasSearched(false); setError(null); } }, [layer]);

    const handleSearch = async () => {
        if (!layer) return showDialog('error', 'Lỗi', 'Vui lòng chọn lớp dữ liệu.');
        setLoading(true);
        setError(null);
        setHasSearched(true);
        try {
            const data = await parcelApi.getAll(layer, searchFilters);
            setParcels(data);
        } catch (err: any) { setError(err.message); setParcels([]); }
        finally { setLoading(false); }
    };

    // --- HELPERS: DATA MAPPING ---
    const getFieldValue = (obj: any, aliases: string[]) => {
        for (const alias of aliases) {
            if (obj[alias] !== undefined && obj[alias] !== null && obj[alias] !== '') return obj[alias];
            const lower = alias.toLowerCase();
            const foundKey = Object.keys(obj).find(k => k.toLowerCase() === lower);
            if (foundKey && obj[foundKey] !== undefined && obj[foundKey] !== null) return obj[foundKey];
        }
        return null;
    };

    // --- ACTIONS ---
    const handleDownload = (p: any) => {
        try {
            const geojson = { type: "Feature", geometry: p.geometry, properties: { gid: p.gid, to: getFieldValue(p, ['sodoto', 'so_to']), thua: getFieldValue(p, ['sothua', 'so_thua']), source: layer } };
            const blob = new Blob([JSON.stringify(geojson, null, 2)], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url; a.download = `Parcel_${p.gid}.geojson`; a.click();
        } catch (err) { showDialog('error', 'Lỗi', 'Không thể xuất file.'); }
    };

    const handleDelete = (gid: number) => {
        showDialog('confirm', 'Xác nhận xóa', 'Bạn có chắc muốn xóa thửa đất này khỏi hệ thống?', async () => {
            setLoading(true);
            try {
                await parcelApi.delete(layer, gid);
                await handleSearch();
                showDialog('success', 'Thành công', 'Đã xóa thửa đất.');
            } catch (err: any) { showDialog('error', 'Lỗi', err.message); }
            finally { setLoading(false); }
        });
    };

    const handleFormSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (editingId) {
                if (formData.file) await parcelApi.createWithUpload(layer, { ...formData, gid: editingId });
                else await parcelApi.update(layer, editingId, formData);
            } else {
                if (formData.file) await parcelApi.createWithUpload(layer, formData);
                else await parcelApi.create(layer, formData);
            }
            setIsFormOpen(false);
            await handleSearch();
            showDialog('success', 'Thành công', 'Dữ liệu đã được lưu trữ.');
        } catch (err: any) { showDialog('error', 'Lỗi', err.message); }
        finally { setLoading(false); }
    };

    const openEdit = (p: any) => {
        setEditingId(p.gid);
        setFormData({ 
            sodoto: getFieldValue(p, ['sodoto', 'so_to']).toString(), 
            sothua: getFieldValue(p, ['sothua', 'so_thua']).toString(), 
            tenchu: getFieldValue(p, ['tenchu', 'owner']), 
            diachi: getFieldValue(p, ['diachi', 'address']), 
            loaidat: getFieldValue(p, ['loaidat', 'kyhieumucd']), 
            dientich: parseFloat(getFieldValue(p, ['dientich', 'area']) || 0),
            geometry: p.geometry, file: null 
        });
        setIsFormOpen(true);
    };

    const openAdd = () => {
        setEditingId(null);
        setFormData({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });
        setIsFormOpen(true);
    };

    return (
        <div className="p-6 bg-gray-950 text-white min-h-full space-y-6 flex flex-col font-sans">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-gray-800 pb-6 gap-4">
                <div className="flex items-center gap-4">
                    <div className="bg-blue-600/20 p-3 rounded-2xl border border-blue-500/30">
                        <Database className="text-blue-500" size={28} />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black tracking-tight uppercase">Quản trị Thửa đất</h2>
                        <div className="flex items-center gap-2 text-gray-500 text-xs mt-0.5 font-bold uppercase tracking-widest">
                            <Layers size={14} className="text-blue-400" />
                            <span>Database: {layer || 'Chờ nạp...'}</span>
                        </div>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button onClick={loadTables} className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 px-4 py-2.5 rounded-xl text-xs font-black transition-all border border-gray-700"><RefreshCw size={16} className={loading ? "animate-spin" : ""} /> TẢI LẠI</button>
                    <button 
                        onClick={() => setIsBulkOpen(true)} 
                        disabled={!layer} 
                        className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-5 py-2.5 rounded-xl text-xs font-black transition-all shadow-lg active:scale-95 disabled:opacity-50"
                    >
                        <FileSpreadsheet size={18} /> NHẬP TỆP DỮ LIỆU
                    </button>
                    <button onClick={openAdd} disabled={!layer} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 px-5 py-2.5 rounded-xl text-xs font-black transition-all shadow-lg active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"><Plus size={18} /> THÊM THỬA ĐẤT</button>
                </div>
            </div>

            <div className="bg-gray-900 rounded-3xl border border-gray-800 shadow-2xl overflow-hidden flex flex-col flex-1">
                <TableFilter layer={layer} setLayer={setLayer} availableTables={availableTables} searchFilters={searchFilters} setSearchFilters={setSearchFilters} handleSearch={handleSearch} loading={loading} />
                <ParcelList parcels={parcels} hasSearched={hasSearched} error={error} loading={loading} onQuickView={(p)=>{setSelectedItem(p); setIsPreviewOpen(true);}} onDownload={handleDownload} onEdit={openEdit} onDelete={handleDelete} getFieldValue={getFieldValue} />
            </div>

            {/* Modals */}
            <ParcelForm isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} editingId={editingId} formData={formData} setFormData={setFormData} handleSubmit={handleFormSubmit} loading={loading} />
            <BulkImportModal isOpen={isBulkOpen} onClose={() => setIsBulkOpen(false)} targetTable={layer} onSuccess={() => { handleSearch(); showDialog('success', 'Thành công', 'Đã nạp toàn bộ dữ liệu từ tệp tin.'); }} />
            {isPreviewOpen && selectedItem && <QuickView parcel={selectedItem} onClose={() => setIsPreviewOpen(false)} onDownload={handleDownload} getFieldValue={getFieldValue} />}

            {/* Dialog System */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2.5rem] w-full max-w-md border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-16 h-16 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={32}/></div>}
                            {dialog.type === 'error' && <div className="w-16 h-16 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={32}/></div>}
                            {dialog.type === 'confirm' && <div className="w-16 h-16 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={32}/></div>}
                            {dialog.type === 'alert' && <div className="w-16 h-16 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={32}/></div>}
                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed mb-8">{dialog.message}</p>
                            <div className="flex gap-3 w-full">
                                {dialog.type === 'confirm' ? (
                                    <><button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3.5 bg-gray-800 hover:bg-gray-700 text-gray-400 rounded-2xl font-black text-xs uppercase tracking-widest">HỦY</button><button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3.5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black text-xs uppercase shadow-lg">ĐỒNG Ý</button></>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black text-xs uppercase shadow-lg">ĐÓNG</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ParcelManager;

import React, { useState, useRef } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParcelDTO[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParcelDTO | null>(null);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParcelDTO[] = features.map((f: any) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    // --- LOGIC CHỈNH SỬA DÒNG ---
    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
    };

    const handleImport = async () => {
        if (parsedData.length === 0) return;

        // Kiểm tra xem còn dòng nào chưa hợp lệ (Thiếu số tờ/thửa)
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất chưa được định danh Số tờ/Số thửa. Vui lòng chỉnh sửa trước khi nạp.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-7xl shadow-2xl flex flex-col max-h-[90vh]">
                <div className="p-6 border-b border-gray-800 flex justify-between items-center bg-gray-950/50">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-3 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={28} />
                        </div>
                        <div>
                            <h3 className="text-xl font-black uppercase text-white leading-none mb-1">Nhập tệp dữ liệu hàng loạt</h3>
                            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> Đích: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={28}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
                    {/* Panel trái: File upload & Stats */}
                    <div className="w-full md:w-80 border-r border-gray-800 p-8 space-y-8 bg-gray-950/20">
                        <div 
                            className={`p-6 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex flex-col items-center gap-4 text-center ${file ? 'border-emerald-500/50 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-900/50'}`}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className={`p-4 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                <FileUp size={32}/>
                            </div>
                            <div>
                                <p className="text-xs font-black text-white uppercase mb-1">{file ? "Thay đổi file" : "Chọn file dữ liệu"}</p>
                                <p className="text-[9px] text-gray-500 font-bold uppercase">ZIP (SHP) hoặc GeoJSON</p>
                            </div>
                            <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                        </div>

                        {parsedData.length > 0 && (
                            <div className="space-y-4 animate-in slide-in-from-left-4 duration-500">
                                <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest border-l-2 border-indigo-500 pl-3">Thống kê dữ liệu</h4>
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Số thửa</p>
                                        <p className="text-xl font-black text-white">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[9px] text-gray-500 font-bold uppercase mb-1">Hợp lệ</p>
                                        <p className="text-xl font-black text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                                <div className="bg-indigo-900/10 border border-indigo-500/20 p-4 rounded-2xl flex items-start gap-3">
                                    <Info className="text-indigo-400 shrink-0" size={16}/>
                                    <p className="text-[9px] text-indigo-300 font-bold uppercase leading-relaxed">Bạn có thể nhấp "Sửa" trên từng dòng để bổ sung thông tin thiếu trước khi Import.</p>
                                </div>
                            </div>
                        )}

                        {error && (
                            <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3">
                                <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                <p className="text-xs text-red-400 font-bold leading-tight">{error}</p>
                            </div>
                        )}
                    </div>

                    {/* Panel phải: Preview table */}
                    <div className="flex-1 bg-gray-900/50 overflow-hidden flex flex-col">
                        {isParsing ? (
                            <div className="flex-1 flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-indigo-500" size={48} />
                                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Đang phân tích cấu trúc file...</p>
                            </div>
                        ) : parsedData.length > 0 ? (
                            <div className="flex-1 flex flex-col overflow-hidden">
                                <div className="flex-1 overflow-auto custom-scrollbar">
                                    <table className="w-full text-xs text-left border-collapse">
                                        <thead className="bg-gray-950 text-gray-500 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                            <tr>
                                                <th className="p-4 w-12 text-center">STT</th>
                                                <th className="p-4 w-28">Số tờ/thửa</th>
                                                <th className="p-4 min-w-[150px]">Chủ sử dụng</th>
                                                <th className="p-4 w-32">Mục đích</th>
                                                <th className="p-4 w-32 text-right">Diện tích (m²)</th>
                                                <th className="p-4 w-24 text-right">Hành động</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-800">
                                            {parsedData.map((p, i) => {
                                                const isEditing = editingIndex === i;
                                                const isInvalid = !p.sodoto || !p.sothua;

                                                return (
                                                    <tr key={i} className={`transition-colors ${isEditing ? 'bg-blue-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}>
                                                        <td className="p-4 text-center text-gray-600 font-mono">{i + 1}</td>

                                                        <td className="p-2">
                                                            {isEditing ? (
                                                                <div className="flex gap-1">
                                                                    <input className="w-12 bg-slate-950 border border-slate-700 rounded px-1 py-1 text-[10px] text-white" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                    <input className="w-12 bg-slate-950 border border-slate-700 rounded px-1 py-1 text-[10px] text-white" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                                </div>
                                                            ) : (
                                                                <span className={`font-black ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                    {p.sodoto || '?'}/{p.sothua || '?'}
                                                                </span>
                                                            )}
                                                        </td>

                                                        <td className="p-2">
                                                            {isEditing ? (
                                                                <input className="w-full bg-slate-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                            ) : (
                                                                <span className="text-gray-300 truncate block max-w-[200px]">{p.tenchu || '--'}</span>
                                                            )}
                                                        </td>

                                                        <td className="p-2">
                                                            {isEditing ? (
                                                                <input className="w-full bg-slate-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white uppercase" value={editBuffer?.loaidat} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                            ) : (
                                                                <span className="bg-gray-800 px-2 py-0.5 rounded text-[9px] font-black border border-gray-700">{p.loaidat || '--'}</span>
                                                            )}
                                                        </td>

                                                        <td className="p-2 text-right">
                                                            {isEditing ? (
                                                                <input type="number" className="w-24 bg-slate-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 text-right font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} />
                                                            ) : (
                                                                <span className="font-mono font-bold text-emerald-500">{p.dientich.toLocaleString()}</span>
                                                            )}
                                                        </td>

                                                        <td className="p-4">
                                                            <div className="flex justify-end gap-2">
                                                                {isEditing ? (
                                                                    <>
                                                                        <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded hover:bg-emerald-500 transition-colors shadow-lg" title="Xác nhận dòng">
                                                                            <Check size={14}/>
                                                                        </button>
                                                                        <button onClick={cancelEditing} className="p-1.5 bg-gray-700 text-gray-300 rounded hover:bg-gray-600 transition-colors" title="Hủy">
                                                                            <X size={14}/>
                                                                        </button>
                                                                    </>
                                                                ) : (
                                                                    <>
                                                                        <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thông tin">
                                                                            <Edit2 size={14}/>
                                                                        </button>
                                                                        <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Xóa dòng">
                                                                            <Trash2 size={14}/>
                                                                        </button>
                                                                    </>
                                                                )}
                                                            </div>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                        </tbody>
                                    </table>
                                </div>
                                <div className="p-6 bg-gray-950 border-t border-gray-800 flex justify-between items-center">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Sẵn sàng: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa đất
                                    </p>
                                    <div className="flex gap-3">
                                        <button onClick={onClose} className="px-6 py-3 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DỮ LIỆU
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center opacity-10 gap-6">
                                <Database size={120} />
                                <p className="text-xl font-black uppercase tracking-[0.4em]">Preview Area</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { getUid } from 'ol/util';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                // Tìm index trong parsedData dựa trên tempId
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        // Cuộn bảng đến dòng được chọn
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            mapInstance.current?.setTarget(undefined);
            mapInstance.current = null;
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features = parsedData.map(p => {
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            });
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000 });
        }
    }, [parsedData.length]); // Chỉ chạy lại khi số lượng thửa thay đổi (load mới hoặc xóa)

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        // Highlight trên bản đồ
        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                selectInteraction.current?.getFeatures().clear();
                selectInteraction.current?.getFeatures().push(feature);
                mapInstance.current.getView().fit(feature.getGeometry()!.getExtent(), { padding: [100, 100, 100, 100], duration: 500 });
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            // Cập nhật lại style trên bản đồ (nếu từ lỗi thành hợp lệ)
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        {/* Map Overlay Controls */}
                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (!isExtentEmpty(extent)) mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA EDITOR TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        {/* Stats & Upload Area */}
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        {/* Editable Table */}
                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Footer Actions */}
                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

// Helper để check extent rỗng
const isExtentEmpty = (extent: any) => {
    if (!extent || extent.length !== 4) return true;
    return extent[0] === Infinity || extent[2] === -Infinity;
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { getUid } from 'ol/util';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                // Tìm index trong parsedData dựa trên tempId
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        // Cuộn bảng đến dòng được chọn
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            mapInstance.current?.setTarget(undefined);
            mapInstance.current = null;
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        // Fix: Explicitly type the features array as Feature[]
        const features: Feature[] = parsedData.map(p => {
            // Fix: Cast the result of format.readFeature to Feature as it may return Feature | Feature[] depending on type definitions
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            }) as Feature;
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000 });
        }
    }, [parsedData.length]); // Chỉ chạy lại khi số lượng thửa thay đổi (load mới hoặc xóa)

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        // Highlight trên bản đồ
        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                selectInteraction.current?.getFeatures().clear();
                selectInteraction.current?.getFeatures().push(feature);
                mapInstance.current.getView().fit(feature.getGeometry()!.getExtent(), { padding: [100, 100, 100, 100], duration: 500 });
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            // Cập nhật lại style trên bản đồ (nếu từ lỗi thành hợp lệ)
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        {/* Map Overlay Controls */}
                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (!isExtentEmpty(extent)) mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA EDITOR TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        {/* Stats & Upload Area */}
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        {/* Editable Table */}
                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Footer Actions */}
                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

// Helper để check extent rỗng
const isExtentEmpty = (extent: any) => {
    if (!extent || extent.length !== 4) return true;
    return extent[0] === Infinity || extent[2] === -Infinity;
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            mapInstance.current?.setTarget(undefined);
            mapInstance.current = null;
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData.map(p => {
            // Chuyển đổi GeoJSON sang đối tượng OL Feature và transform tọa độ sang 3857
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            }, {
                dataProjection: 'EPSG:4326',
                featureProjection: 'EPSG:3857'
            }) as Feature;
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            if (!isExtentEmpty(extent)) {
                mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000 });
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            // Tính diện tích trên mặt cầu (EPSG:4326) trước khi transform
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);
                    // Sử dụng geometry trực tiếp thay vì gọi getExtent() thủ công để tránh lỗi type
                    mapInstance.current.getView().fit(geom, { padding: [100, 100, 100, 100], duration: 500 });
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (!isExtentEmpty(extent)) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            mapInstance.current?.setTarget(undefined);
            mapInstance.current = null;
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData.map(p => {
            // Chuyển đổi GeoJSON sang đối tượng OL Feature và transform tọa độ sang 3857
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            }, {
                dataProjection: 'EPSG:4326',
                featureProjection: 'EPSG:3857'
            }) as Feature;
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            if (!isExtentEmpty(extent)) {
                mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000 });
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            // Tính diện tích trên mặt cầu (EPSG:4326) trước khi transform
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);
                    // Sử dụng geometry trực tiếp thay vì gọi getExtent() thủ công để tránh lỗi type
                    // Fix: Cast geom to any because ol's Geometry type might be missing SimpleGeometry properties needed for fit()
                    mapInstance.current.getView().fit(geom as any, { padding: [100, 100, 100, 100], duration: 500 });
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (!isExtentEmpty(extent)) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        // Map không cần lớp nền (Basemap) theo yêu cầu
        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            mapInstance.current?.setTarget(undefined);
            mapInstance.current = null;
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData.map(p => {
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            }, {
                dataProjection: 'EPSG:4326',
                featureProjection: 'EPSG:3857'
            }) as Feature;
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            // Kiểm tra extent hợp lệ trước khi fit để tránh lỗi l.getExtent is not a function
            if (extent && !isExtentEmpty(extent) && extent[0] !== Infinity) {
                mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000 });
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);
                    // Sử dụng extent của geometry để fit view an toàn hơn
                    const extent = geom.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        mapInstance.current.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 500 });
                    }
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (extent && !isExtentEmpty(extent) && extent[0] !== Infinity) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        // Khởi tạo bản đồ KHÔNG CÓ TileLayer (Bản đồ nền) theo yêu cầu
        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            if (mapInstance.current) {
                mapInstance.current.setTarget(undefined);
                mapInstance.current = null;
            }
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData.map(p => {
            const feature = format.readFeature({
                type: 'Feature',
                geometry: p.geometry,
                properties: { ...p }
            }, {
                dataProjection: 'EPSG:4326',
                featureProjection: 'EPSG:3857'
            }) as Feature;
            feature.set('tempId', p.tempId);
            return feature;
        });

        vectorSource.current.addFeatures(features);

        if (features.length > 0) {
            const extent = vectorSource.current.getExtent();
            // Phòng tránh lỗi l.getExtent is not a function bằng cách kiểm tra extent kỹ lưỡng
            if (extent && !isExtentEmpty(extent) && Number.isFinite(extent[0])) {
                mapInstance.current.getView().fit(extent, { 
                    padding: [50, 50, 50, 50], 
                    duration: 1000 
                });
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features.map((f: any, index: number) => {
            const props = f.properties || {};
            const olGeom = format.readGeometry(f.geometry);
            let area = 0;
            if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);

            const findVal = (keys: string[]) => {
                for (const k of keys) {
                    const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                    if (foundKey && props[foundKey]) return props[foundKey];
                }
                return '';
            };

            return {
                tempId: `tmp-${Date.now()}-${index}`,
                sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                diachi: findVal(['diachi', 'address', 'location']),
                dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                geometry: f.geometry
            };
        });

        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);
                    const extent = geom.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        mapInstance.current.getView().fit(extent, { 
                            padding: [100, 100, 100, 100], 
                            duration: 500 
                        });
                    }
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP (No Basemap) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        {/* Map Overlay Controls */}
                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (extent && !isExtentEmpty(extent) && Number.isFinite(extent[0])) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA EDITOR TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        {/* Stats & Upload Area */}
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        {/* Editable Table */}
                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Footer Actions */}
                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 2
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 4 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current || mapInstance.current) return;

        // Khởi tạo bản đồ KHÔNG CÓ TileLayer (Bản đồ nền) theo yêu cầu
        // Background sẽ là màu nền của div container (đen/xám)
        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        return () => {
            if (mapInstance.current) {
                mapInstance.current.setTarget(undefined);
                mapInstance.current = null;
            }
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData
            .filter(p => p.geometry) // Chỉ lấy các parcel có geometry
            .map(p => {
                try {
                    const feature = format.readFeature({
                        type: 'Feature',
                        geometry: p.geometry,
                        properties: { ...p }
                    }, {
                        dataProjection: 'EPSG:4326',
                        featureProjection: 'EPSG:3857'
                    }) as Feature;
                    feature.set('tempId', p.tempId);
                    return feature;
                } catch (err) {
                    return null;
                }
            })
            .filter(Boolean) as Feature[];

        if (features.length > 0) {
            vectorSource.current.addFeatures(features);

            // Safe fit using extent array
            const extent = vectorSource.current.getExtent();
            if (Array.isArray(extent) && !isExtentEmpty(extent) && Number.isFinite(extent[0]) && Number.isFinite(extent[2])) {
                try {
                    mapInstance.current.getView().fit(extent, { 
                        padding: [50, 50, 50, 50], 
                        duration: 1000 
                    });
                } catch (e) {
                    console.warn("Map fit error:", e);
                }
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features
            .filter((f: any) => f.geometry) // Lọc bỏ feature không có hình học
            .map((f: any, index: number) => {
                const props = f.properties || {};
                let area = 0;
                try {
                    const olGeom = format.readGeometry(f.geometry);
                    if (olGeom instanceof Polygon || olGeom instanceof MultiPolygon) area = getArea(olGeom);
                } catch (e) {}

                const findVal = (keys: string[]) => {
                    for (const k of keys) {
                        const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                        if (foundKey && props[foundKey]) return props[foundKey];
                    }
                    return '';
                };

                return {
                    tempId: `tmp-${Date.now()}-${index}`,
                    sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                    sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                    tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                    loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                    diachi: findVal(['diachi', 'address', 'location']),
                    dientich: area > 0 ? Math.round(area * 100) / 100 : 0,
                    geometry: f.geometry
                };
            });

        if (results.length === 0) {
            setError("Không tìm thấy đối tượng không gian hợp lệ.");
        }
        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);

                    const extent = geom.getExtent();
                    if (Array.isArray(extent) && !isExtentEmpty(extent)) {
                        try {
                            mapInstance.current.getView().fit(extent, { 
                                padding: [100, 100, 100, 100], 
                                duration: 500 
                            });
                        } catch (e) { console.warn(e); }
                    }
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP (No Basemap) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        {/* Map Overlay Controls */}
                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (Array.isArray(extent) && !isExtentEmpty(extent) && Number.isFinite(extent[0])) {
                                     try {
                                         mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                     } catch(e){}
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA EDITOR TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        {/* Stats & Upload Area */}
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        {/* Editable Table */}
                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Footer Actions */}
                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, Info, Trash2, Edit2, Check, Save, MousePointer2, Maximize } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Đăng ký VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM) để xử lý file GeoJSON tọa độ phẳng
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string; // ID tạm để map giữa OL Feature và React State
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- HELPERS ---
    // Hàm lấy tọa độ đầu tiên để kiểm tra hệ tọa độ (WGS84 hay VN2000)
    const getFirstCoordinate = (geometry: any): number[] | null => {
        if (!geometry || !geometry.coordinates) return null;
        let coords = geometry.coordinates;
        // Đi sâu vào mảng để lấy cặp tọa độ [x, y] đầu tiên
        while (Array.isArray(coords) && Array.isArray(coords[0])) {
            coords = coords[0];
        }
        // coords bây giờ là [x, y] hoặc [x, y, z]
        return (Array.isArray(coords) && coords.length >= 2 && typeof coords[0] === 'number') ? [coords[0], coords[1]] : null;
    };

    // --- STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 1.5
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 3 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen || !mapElement.current) return;

        // Nếu map đã khởi tạo, chỉ cần resize
        if (mapInstance.current) {
            setTimeout(() => mapInstance.current?.updateSize(), 200);
            return;
        }

        // Khởi tạo bản đồ KHÔNG CÓ TileLayer (Bản đồ nền)
        const map = new Map({
            target: mapElement.current,
            layers: [
                new VectorLayer({
                    source: vectorSource.current,
                    style: getParcelStyle,
                    zIndex: 10
                })
            ],
            view: new View({ center: [0, 0], zoom: 2 }),
            controls: []
        });

        const select = new Select({
            condition: click,
            style: selectedStyle
        });
        map.addInteraction(select);

        select.on('select', (e) => {
            const feature = e.selected[0];
            if (feature) {
                const tempId = feature.get('tempId');
                setParsedData(current => {
                    const idx = current.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...current[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    return current;
                });
            }
        });

        selectInteraction.current = select;
        mapInstance.current = map;

        // ResizeObserver để tự động cập nhật kích thước map khi container thay đổi
        const resizeObserver = new ResizeObserver(() => {
            map.updateSize();
        });
        resizeObserver.observe(mapElement.current);

        return () => {
            resizeObserver.disconnect();
            if (mapInstance.current) {
                mapInstance.current.setTarget(undefined);
                mapInstance.current = null;
            }
        };
    }, [isOpen]);

    // Cập nhật hiển thị bản đồ khi dữ liệu thay đổi
    useEffect(() => {
        if (!mapInstance.current) return;

        vectorSource.current.clear();
        const format = new GeoJSON();

        const features: Feature[] = parsedData
            .filter(p => p.geometry)
            .map(p => {
                try {
                    // Tự động phát hiện hệ tọa độ dựa trên dữ liệu
                    let dataProjection = 'EPSG:4326';
                    const sampleCoord = getFirstCoordinate(p.geometry);

                    if (sampleCoord) {
                        const [x, y] = sampleCoord;
                        // Nếu tọa độ lớn (VN2000 thường > 100,000), dùng hệ quy chiếu phẳng VN2000
                        if (x > 180 || x < -180 || y > 90 || y < -90) {
                            dataProjection = 'EPSG:9210';
                        }
                    }

                    const feature = format.readFeature({
                        type: 'Feature',
                        geometry: p.geometry,
                        properties: { ...p }
                    }, {
                        dataProjection: dataProjection,
                        featureProjection: 'EPSG:3857' // Map view luôn là Web Mercator
                    }) as Feature;

                    feature.set('tempId', p.tempId);
                    return feature;
                } catch (err) {
                    console.warn("Lỗi đọc feature:", err);
                    return null;
                }
            })
            .filter(Boolean) as Feature[];

        if (features.length > 0) {
            vectorSource.current.addFeatures(features);

            // Lấy extent và kiểm tra tính hợp lệ trước khi fit
            const extent = vectorSource.current.getExtent();
            const isValidExtent = (ext: number[]) => {
                return Array.isArray(ext) && 
                       ext.length === 4 && 
                       ext.every(val => Number.isFinite(val)) &&
                       !isExtentEmpty(ext);
            };

            if (isValidExtent(extent)) {
                try {
                    mapInstance.current.getView().fit(extent, { 
                        padding: [50, 50, 50, 50], 
                        duration: 1000 
                    });
                } catch (e) {
                    console.error("Map fit error:", e);
                }
            }
        }
    }, [parsedData.length]);

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err) { setError("Lỗi giải mã Shapefile."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const format = new GeoJSON();
        const results: ParsedParcel[] = features
            .filter((f: any) => f.geometry) // Lọc bỏ feature không có hình học
            .map((f: any, index: number) => {
                const props = f.properties || {};
                let area = 0;

                // Xác định hệ tọa độ cho việc tính diện tích (nếu cần)
                // Tuy nhiên, ta ưu tiên lấy diện tích từ thuộc tính nếu có
                // Nếu không có, OL sphere.getArea chỉ đúng với EPSG:4326

                const findVal = (keys: string[]) => {
                    for (const k of keys) {
                        const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                        if (foundKey && props[foundKey]) return props[foundKey];
                    }
                    return '';
                };

                // Lấy diện tích từ thuộc tính trước
                let areaVal = parseFloat(findVal(['dientich', 'dien_tich', 'shape_area', 'area', 'dt_phaply']));
                if (!areaVal || isNaN(areaVal)) {
                    // Nếu không có, thử tính toán (lưu ý: có thể không chính xác nếu là hệ tọa độ phẳng mà không transform)
                    try {
                        // Tạm thời bỏ qua tính toán diện tích chính xác ở đây để tránh lỗi transform phức tạp
                        // Nếu cần, có thể dùng geometry.getArea() nếu đã read thành công
                        areaVal = 0; 
                    } catch(e) {}
                }

                return {
                    tempId: `tmp-${Date.now()}-${index}`,
                    sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando']).toString(),
                    sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                    tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                    loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                    diachi: findVal(['diachi', 'address', 'location']),
                    dientich: areaVal > 0 ? Math.round(areaVal * 100) / 100 : 0,
                    geometry: f.geometry
                };
            });

        if (results.length === 0) {
            setError("Không tìm thấy đối tượng không gian hợp lệ.");
        }
        setParsedData(results);
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        if (mapInstance.current) {
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
            if (feature) {
                const geom = feature.getGeometry();
                if (geom) {
                    selectInteraction.current?.getFeatures().clear();
                    selectInteraction.current?.getFeatures().push(feature);

                    const extent = geom.getExtent();
                    if (Array.isArray(extent) && extent.every(v => Number.isFinite(v))) {
                        try {
                            mapInstance.current.getView().fit(extent, { 
                                padding: [100, 100, 100, 100], 
                                duration: 500 
                            });
                        } catch (e) { console.warn(e); }
                    }
                }
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
                feature.changed();
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất lỗi (màu đỏ). Vui lòng nhấp vào chúng trên bản đồ để sửa.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex bg-gray-900 px-4 py-2 rounded-xl border border-gray-800 items-center gap-3">
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Hợp lệ</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Thiếu tin</span></div>
                            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-orange-500"></div><span className="text-[9px] font-black text-gray-400 uppercase">Đang sửa</span></div>
                        </div>
                        <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP (No Basemap) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        <div ref={mapElement} className="w-full h-full" />

                        {/* Map Overlay Controls */}
                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất trên bản đồ <br/> để định danh dữ liệu nhanh.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (Array.isArray(extent) && extent.every(v => Number.isFinite(v)) && !isExtentEmpty(extent)) {
                                     try {
                                         mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                     } catch(e){}
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA EDITOR TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        {/* Stats & Upload Area */}
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-right-4">
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Tổng số thửa</p>
                                        <p className="text-xl font-black text-white leading-none">{parsedData.length}</p>
                                    </div>
                                    <div className="bg-gray-950 p-4 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1 tracking-widest">Hợp lệ (Xanh)</p>
                                        <p className="text-xl font-black text-emerald-500 leading-none">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        {/* Editable Table */}
                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin chi tiết</th>
                                            <th className="p-4 w-20"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>

                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <div className="flex gap-1">
                                                                    <input className="flex-1 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                                    <input type="number" className="w-20 bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-emerald-400 font-mono" value={editBuffer?.dientich} onChange={e=>setEditBuffer({...editBuffer!, dientich: parseFloat(e.target.value)})} placeholder="m²" />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên chủ</span>}</p>
                                                                <div className="flex items-center gap-2">
                                                                    <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                                    <span className="text-[10px] font-mono text-emerald-500 font-bold">{p.dientich.toLocaleString()} m²</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </td>

                                                    <td className="p-4">
                                                        <div className="flex justify-end gap-2">
                                                            {isEditing ? (
                                                                <>
                                                                    <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 shadow-lg" title="Lưu dòng">
                                                                        <Check size={14}/>
                                                                    </button>
                                                                    <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded-lg hover:bg-gray-700" title="Hủy">
                                                                        <X size={14}/>
                                                                    </button>
                                                                </>
                                                            ) : (
                                                                <>
                                                                    <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400 transition-colors" title="Sửa thửa đất">
                                                                        <Edit2 size={14}/>
                                                                    </button>
                                                                    <button onClick={() => setParsedData(prev => prev.filter((_, idx)=>idx !== i))} className="p-1.5 text-gray-500 hover:text-red-500 transition-colors" title="Loại bỏ">
                                                                        <Trash2 size={14}/>
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            {/* Footer Actions */}
                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex flex-col gap-4">
                                <div className="flex justify-between items-center px-1">
                                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">
                                        Trạng thái: <span className="text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</span> / <span className="text-white">{parsedData.length}</span> thửa sẵn sàng
                                    </p>
                                    <div className="flex gap-2">
                                        <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                        <button 
                                            onClick={handleImport} 
                                            disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                        >
                                            {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                            XÁC NHẬN NẠP DB
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, MousePointer2, Maximize, Trash2, Edit2, Check } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Đăng ký hệ tọa độ VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
// Lưu ý: Nếu dữ liệu ở tỉnh khác, cần đổi +lon_0
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string;
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- MAP STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6', // Đỏ nếu lỗi, Xanh nếu ok
                width: 1.5
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 3 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen) return;

        // Xử lý "No map visible": Chờ DOM render xong mới init map
        const timer = setTimeout(() => {
            if (!mapElement.current) return;

            // Nếu đã có map thì update size rồi return, không tạo mới
            if (mapInstance.current) {
                mapInstance.current.updateSize();
                return;
            }

            // Init Map - KHÔNG CÓ TileLayer (Bản đồ nền)
            const map = new Map({
                target: mapElement.current,
                layers: [
                    new VectorLayer({
                        source: vectorSource.current,
                        style: getParcelStyle,
                        zIndex: 10
                    })
                ],
                view: new View({ 
                    center: [0, 0], 
                    zoom: 2,
                    projection: 'EPSG:3857' // Web Mercator chuẩn
                }),
                controls: []
            });

            // Interaction
            const select = new Select({
                condition: click,
                style: selectedStyle
            });
            map.addInteraction(select);

            select.on('select', (e) => {
                const feature = e.selected[0];
                if (feature) {
                    const tempId = feature.get('tempId');
                    // Scroll tới dòng trong bảng
                    const idx = parsedData.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...parsedData[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                }
            });

            selectInteraction.current = select;
            mapInstance.current = map;

            // Resize Observer để fix lỗi width/height = 0 khi resize cửa sổ
            const resizeObserver = new ResizeObserver(() => {
                map.updateSize();
            });
            resizeObserver.observe(mapElement.current);

        }, 300); // Delay 300ms để modal animation hoàn tất

        return () => clearTimeout(timer);
    }, [isOpen]); // Chạy lại khi isOpen thay đổi

    // --- RENDER FEATURES TO MAP ---
    useEffect(() => {
        if (!mapInstance.current || parsedData.length === 0) {
            vectorSource.current.clear();
            return;
        }

        vectorSource.current.clear();
        const format = new GeoJSON();
        const features: Feature[] = [];

        parsedData.forEach(p => {
            if (!p.geometry) return;
            try {
                // Xác định hệ tọa độ đầu vào. 
                // Nếu tọa độ lớn (VD: > 180), giả định là VN-2000 (EPSG:9210)
                let dataProj = 'EPSG:4326';
                const coords = getFirstCoordinate(p.geometry);
                if (coords && (Math.abs(coords[0]) > 180 || Math.abs(coords[1]) > 90)) {
                    dataProj = 'EPSG:9210';
                }

                // Đọc và chuyển đổi sang EPSG:3857 để hiển thị trên web
                const feature = format.readFeature({
                    type: 'Feature',
                    geometry: p.geometry,
                    properties: { ...p }
                }, {
                    dataProjection: dataProj,
                    featureProjection: 'EPSG:3857'
                }) as Feature;

                feature.set('tempId', p.tempId);
                features.push(feature);
            } catch (err) {
                console.warn("Lỗi đọc feature:", err);
            }
        });

        if (features.length > 0) {
            vectorSource.current.addFeatures(features);

            // Safe Fit: Kiểm tra extent hợp lệ trước khi zoom
            const extent = vectorSource.current.getExtent();
            const isValidExtent = (ext: number[]) => {
                return Array.isArray(ext) && ext.length === 4 && ext.every(num => Number.isFinite(num));
            };

            if (isValidExtent(extent) && !isExtentEmpty(extent)) {
                // Dùng requestAnimationFrame để đảm bảo map đã ready
                requestAnimationFrame(() => {
                    mapInstance.current?.getView().fit(extent, { 
                        padding: [50, 50, 50, 50], 
                        duration: 1000 
                    });
                });
            }
        }
    }, [parsedData]); // Chạy lại khi dữ liệu thay đổi

    const getFirstCoordinate = (geometry: any): number[] | null => {
        if (!geometry || !geometry.coordinates) return null;
        const flatCoords = geometry.coordinates.flat(Infinity);
        if (flatCoords.length >= 2) return [flatCoords[0], flatCoords[1]];
        return null;
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err: any) { setError("Lỗi giải mã Shapefile: " + err.message); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err: any) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (!features || features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const results: ParsedParcel[] = features
            .filter((f: any) => f.geometry)
            .map((f: any, index: number) => {
                const props = f.properties || {};

                // Helper tìm giá trị không phân biệt hoa thường
                const findVal = (keys: string[]) => {
                    for (const k of keys) {
                        const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                        if (foundKey && props[foundKey]) return props[foundKey];
                    }
                    return '';
                };

                // Lấy diện tích từ thuộc tính trước, nếu không có mới tính toán
                let areaVal = parseFloat(findVal(['dientich', 'dien_tich', 'shape_area', 'area']));
                if (!areaVal && f.geometry) {
                    // Ước lượng sơ bộ (Lưu ý: getArea này tính trên Sphere WebMercator nếu chưa transform)
                    try {
                       // Không tính toán ở đây để tránh lỗi transform phức tạp, ưu tiên dữ liệu có sẵn
                       areaVal = 0; 
                    } catch(e) {}
                }

                return {
                    tempId: `tmp-${Date.now()}-${index}`,
                    sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando', 'shmap']).toString(),
                    sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                    tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                    loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                    diachi: findVal(['diachi', 'address', 'location']),
                    dientich: areaVal > 0 ? Math.round(areaVal * 100) / 100 : 0,
                    geometry: f.geometry
                };
            });

        if (results.length === 0) {
            setError("Không tìm thấy đối tượng không gian hợp lệ.");
        } else {
            setParsedData(results);
        }
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        // Zoom to feature
        const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
        if (feature) {
            selectInteraction.current?.getFeatures().clear();
            selectInteraction.current?.getFeatures().push(feature);
            const extent = feature.getGeometry()?.getExtent();
            if (extent) {
                mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 500 });
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            // Cập nhật lại thuộc tính trên bản đồ để đổi màu nếu hết lỗi
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất thiếu Số Tờ/Số Thửa (màu đỏ). Vui lòng sửa trước khi nạp.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP (No Basemap) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        {/* Quan trọng: Thêm minHeight để tránh lỗi 0 height */}
                        <div ref={mapElement} className="w-full h-full min-h-[400px]" />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất để sửa thông tin.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (extent && extent.every(Number.isFinite) && !isExtentEmpty(extent)) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="flex gap-4">
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Tổng số</p>
                                        <p className="text-lg font-black text-white">{parsedData.length}</p>
                                    </div>
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Hợp lệ</p>
                                        <p className="text-lg font-black text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin</th>
                                            <th className="p-4 w-16"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên</span>}</p>
                                                                <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                            </div>
                                                        )}
                                                    </td>
                                                    <td className="p-2 text-right">
                                                        {isEditing ? (
                                                            <div className="flex gap-1 justify-end">
                                                                <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded hover:bg-emerald-500"><Check size={14}/></button>
                                                                <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded hover:bg-gray-700"><X size={14}/></button>
                                                            </div>
                                                        ) : (
                                                            <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400"><Edit2 size={14}/></button>
                                                        )}
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex justify-end gap-2">
                                <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                <button 
                                    onClick={handleImport} 
                                    disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                    className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                >
                                    {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                    XÁC NHẬN NẠP DB
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, MousePointer2, Maximize, Trash2, Edit2, Check } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import { getArea } from 'ol/sphere';
import GeoJSON from 'ol/format/GeoJSON';
import { Polygon, MultiPolygon } from 'ol/geom';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Đăng ký hệ tọa độ VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
// Lưu ý: Nếu dữ liệu ở tỉnh khác, cần đổi +lon_0
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string;
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- MAP STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6', // Đỏ nếu lỗi, Xanh nếu ok
                width: 1.5
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 3 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen) return;

        // Xử lý "No map visible": Chờ DOM render xong mới init map
        const timer = setTimeout(() => {
            if (!mapElement.current) return;

            // Nếu đã có map thì update size rồi return, không tạo mới
            if (mapInstance.current) {
                mapInstance.current.updateSize();
                return;
            }

            // Init Map - KHÔNG CÓ TileLayer (Bản đồ nền)
            const map = new Map({
                target: mapElement.current,
                layers: [
                    new VectorLayer({
                        source: vectorSource.current,
                        style: getParcelStyle,
                        zIndex: 10
                    })
                ],
                view: new View({ 
                    center: [0, 0], 
                    zoom: 2,
                    projection: 'EPSG:3857' // Web Mercator chuẩn
                }),
                controls: []
            });

            // Interaction
            const select = new Select({
                condition: click,
                style: selectedStyle
            });
            map.addInteraction(select);

            select.on('select', (e) => {
                const feature = e.selected[0];
                if (feature) {
                    const tempId = feature.get('tempId');
                    // Scroll tới dòng trong bảng
                    const idx = parsedData.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...parsedData[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                }
            });

            selectInteraction.current = select;
            mapInstance.current = map;

            // Resize Observer để fix lỗi width/height = 0 khi resize cửa sổ
            const resizeObserver = new ResizeObserver(() => {
                map.updateSize();
            });
            resizeObserver.observe(mapElement.current);

        }, 300); // Delay 300ms để modal animation hoàn tất

        return () => clearTimeout(timer);
    }, [isOpen]); // Chạy lại khi isOpen thay đổi

    // --- RENDER FEATURES TO MAP ---
    useEffect(() => {
        if (!mapInstance.current || parsedData.length === 0) {
            vectorSource.current.clear();
            return;
        }

        vectorSource.current.clear();
        const format = new GeoJSON();
        const features: Feature[] = [];

        parsedData.forEach(p => {
            if (!p.geometry) return;
            try {
                // Xác định hệ tọa độ đầu vào. 
                // Nếu tọa độ lớn (VD: > 180), giả định là VN-2000 (EPSG:9210)
                let dataProj = 'EPSG:4326';
                const coords = getFirstCoordinate(p.geometry);
                if (coords && (Math.abs(coords[0]) > 180 || Math.abs(coords[1]) > 90)) {
                    dataProj = 'EPSG:9210';
                }

                // Đọc và chuyển đổi sang EPSG:3857 để hiển thị trên web
                const feature = format.readFeature({
                    type: 'Feature',
                    geometry: p.geometry,
                    properties: { ...p }
                }, {
                    dataProjection: dataProj,
                    featureProjection: 'EPSG:3857'
                }) as Feature;

                feature.set('tempId', p.tempId);
                features.push(feature);
            } catch (err) {
                console.warn("Lỗi đọc feature:", err);
            }
        });

        if (features.length > 0) {
            vectorSource.current.addFeatures(features);

            // Safe Fit: Kiểm tra extent hợp lệ trước khi zoom
            const extent = vectorSource.current.getExtent();
            const isValidExtent = (ext: number[]) => {
                return Array.isArray(ext) && ext.length === 4 && ext.every(num => Number.isFinite(num));
            };

            if (isValidExtent(extent) && !isExtentEmpty(extent)) {
                // Dùng requestAnimationFrame để đảm bảo map đã ready
                requestAnimationFrame(() => {
                    mapInstance.current?.getView().fit(extent, { 
                        padding: [50, 50, 50, 50], 
                        duration: 1000 
                    });
                });
            }
        }
    }, [parsedData]); // Chạy lại khi dữ liệu thay đổi

    const getFirstCoordinate = (geometry: any): number[] | null => {
        if (!geometry || !geometry.coordinates) return null;
        const flatCoords = geometry.coordinates.flat(Infinity);
        if (flatCoords.length >= 2) return [flatCoords[0], flatCoords[1]];
        return null;
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err: any) { setError("Lỗi giải mã Shapefile: " + err.message); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const content = JSON.parse(event.target?.result as string);
                        processGeoJSON(content);
                    } catch (err: any) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (!features || features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const results: ParsedParcel[] = features
            .filter((f: any) => f.geometry)
            .map((f: any, index: number) => {
                const props = f.properties || {};

                // Helper tìm giá trị không phân biệt hoa thường
                const findVal = (keys: string[]) => {
                    for (const k of keys) {
                        const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                        if (foundKey && props[foundKey]) return props[foundKey];
                    }
                    return '';
                };

                // Lấy diện tích từ thuộc tính trước, nếu không có mới tính toán
                let areaVal = parseFloat(findVal(['dientich', 'dien_tich', 'shape_area', 'area']));
                if (!areaVal && f.geometry) {
                    // Ước lượng sơ bộ (Lưu ý: getArea này tính trên Sphere WebMercator nếu chưa transform)
                    try {
                       // Không tính toán ở đây để tránh lỗi transform phức tạp, ưu tiên dữ liệu có sẵn
                       areaVal = 0; 
                    } catch(e) {}
                }

                return {
                    tempId: `tmp-${Date.now()}-${index}`,
                    sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando', 'shmap']).toString(),
                    sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                    tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                    loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                    diachi: findVal(['diachi', 'address', 'location']),
                    dientich: areaVal > 0 ? Math.round(areaVal * 100) / 100 : 0,
                    geometry: f.geometry
                };
            });

        if (results.length === 0) {
            setError("Không tìm thấy đối tượng không gian hợp lệ.");
        } else {
            setParsedData(results);
        }
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        // Zoom to feature
        const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
        if (feature) {
            selectInteraction.current?.getFeatures().clear();
            selectInteraction.current?.getFeatures().push(feature);
            const extent = feature.getGeometry()?.getExtent();
            if (extent) {
                mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 500 });
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            // Cập nhật lại thuộc tính trên bản đồ để đổi màu nếu hết lỗi
            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất thiếu Số Tờ/Số Thửa (màu đỏ). Vui lòng sửa trước khi nạp.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: INTERACTIVE MAP (No Basemap) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group">
                        {/* Quan trọng: Thêm minHeight để tránh lỗi 0 height */}
                        <div ref={mapElement} className="w-full h-full min-h-[400px]" />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất để sửa thông tin.</p>
                             </div>
                             <button onClick={() => {
                                 const extent = vectorSource.current.getExtent();
                                 if (extent && extent.every(Number.isFinite) && !isExtentEmpty(extent)) {
                                     mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="flex gap-4">
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Tổng số</p>
                                        <p className="text-lg font-black text-white">{parsedData.length}</p>
                                    </div>
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Hợp lệ</p>
                                        <p className="text-lg font-black text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin</th>
                                            <th className="p-4 w-16"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên</span>}</p>
                                                                <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                            </div>
                                                        )}
                                                    </td>
                                                    <td className="p-2 text-right">
                                                        {isEditing ? (
                                                            <div className="flex gap-1 justify-end">
                                                                <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded hover:bg-emerald-500"><Check size={14}/></button>
                                                                <button onClick={cancelEditing} className="p-1.5 bg-gray-800 text-gray-400 rounded hover:bg-gray-700"><X size={14}/></button>
                                                            </div>
                                                        ) : (
                                                            <button onClick={() => startEditing(i)} className="p-1.5 text-gray-500 hover:text-blue-400"><Edit2 size={14}/></button>
                                                        )}
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>

                            <div className="p-6 bg-gray-950 border-t border-gray-800 flex justify-end gap-2">
                                <button onClick={onClose} className="px-4 py-2 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest">HỦY BỎ</button>
                                <button 
                                    onClick={handleImport} 
                                    disabled={importing || parsedData.length === 0 || editingIndex !== null}
                                    className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-3 rounded-2xl font-black text-[11px] uppercase tracking-[0.1em] shadow-xl shadow-indigo-900/30 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                                >
                                    {importing ? <Loader2 className="animate-spin" size={16}/> : <CheckCircle2 size={16}/>}
                                    XÁC NHẬN NẠP DB
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BulkImportModal;

import React, { useState, useRef, useEffect } from 'react';
import { X, FileUp, Database, Loader2, CheckCircle2, AlertTriangle, Layers, MousePointer2, Maximize, Trash2, Edit2, Check } from 'lucide-react';
import { parcelApi, ParcelDTO } from '../../../services/parcelApi';
import shp from 'shpjs';
import GeoJSON from 'ol/format/GeoJSON';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import { Vector as VectorLayer } from 'ol/layer';
import { Vector as VectorSource } from 'ol/source';
import * as style from 'ol/style';
import Feature from 'ol/Feature';
import { Select } from 'ol/interaction';
import { click } from 'ol/events/condition';
import { isEmpty as isExtentEmpty } from 'ol/extent';

// Đăng ký hệ tọa độ VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
// QUAN TRỌNG: Định nghĩa này phải khớp với dữ liệu đầu vào
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

interface BulkImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    targetTable: string;
    onSuccess: () => void;
}

interface ParsedParcel extends ParcelDTO {
    tempId: string;
}

const BulkImportModal: React.FC<BulkImportModalProps> = ({ isOpen, onClose, targetTable, onSuccess }) => {
    const [file, setFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parsedData, setParsedData] = useState<ParsedParcel[]>([]);
    const [importing, setImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Map Refs
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const vectorSource = useRef<VectorSource>(new VectorSource());
    const selectInteraction = useRef<Select | null>(null);

    // Editing State
    const [editingIndex, setEditingIndex] = useState<number | null>(null);
    const [editBuffer, setEditBuffer] = useState<ParsedParcel | null>(null);

    // --- MAP STYLES ---
    const getParcelStyle = (feature: any) => {
        const props = feature.getProperties();
        const isInvalid = !props.sodoto || !props.sothua;

        return new style.Style({
            stroke: new style.Stroke({
                color: isInvalid ? '#ef4444' : '#3b82f6',
                width: 1.5
            }),
            fill: new style.Fill({
                color: isInvalid ? 'rgba(239, 68, 68, 0.1)' : 'rgba(59, 130, 246, 0.1)'
            })
        });
    };

    const selectedStyle = new style.Style({
        stroke: new style.Stroke({ color: '#f97316', width: 3 }),
        fill: new style.Fill({ color: 'rgba(249, 115, 22, 0.3)' }),
        zIndex: 100
    });

    // --- MAP INITIALIZATION ---
    useEffect(() => {
        if (!isOpen) return;

        // Force delay để DOM render xong hoàn toàn
        const timer = setTimeout(() => {
            if (!mapElement.current) return;

            // Xóa map cũ nếu có để tránh lỗi duplicate
            if (mapInstance.current) {
                mapInstance.current.setTarget(undefined);
                mapInstance.current = null;
            }

            vectorSource.current.clear(); // Clear source cũ

            const map = new Map({
                target: mapElement.current,
                layers: [
                    // CHỈ DÙNG VECTOR LAYER, KHÔNG CÓ TILE NỀN
                    new VectorLayer({
                        source: vectorSource.current,
                        style: getParcelStyle,
                        zIndex: 10
                    })
                ],
                view: new View({ 
                    center: [0, 0], 
                    zoom: 2,
                    projection: 'EPSG:3857' // Web Mercator cho hiển thị
                }),
                controls: []
            });

            const select = new Select({
                condition: click,
                style: selectedStyle
            });
            map.addInteraction(select);

            select.on('select', (e) => {
                const feature = e.selected[0];
                if (feature) {
                    const tempId = feature.get('tempId');
                    const idx = parsedData.findIndex(p => p.tempId === tempId);
                    if (idx !== -1) {
                        setEditingIndex(idx);
                        setEditBuffer({ ...parsedData[idx] });
                        document.getElementById(`row-${tempId}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                }
            });

            selectInteraction.current = select;
            mapInstance.current = map;

            // ResizeObserver
            const resizeObserver = new ResizeObserver(() => {
                if (mapInstance.current) mapInstance.current.updateSize();
            });
            resizeObserver.observe(mapElement.current);

            return () => resizeObserver.disconnect();

        }, 300);

        return () => clearTimeout(timer);
    }, [isOpen]);

    // --- RENDER DỮ LIỆU LÊN MAP ---
    useEffect(() => {
        if (!mapInstance.current || parsedData.length === 0) {
            vectorSource.current.clear();
            return;
        }

        vectorSource.current.clear();

        // Tạo GeoJSON Format Reader
        const format = new GeoJSON();
        const features: Feature[] = [];

        parsedData.forEach(p => {
            if (!p.geometry) return;
            try {
                // Đọc Geometry: Input là VN2000 (9210), Output lên Map là WebMercator (3857)
                const feature = format.readFeature({
                    type: 'Feature',
                    geometry: p.geometry,
                    properties: { ...p }
                }, {
                    dataProjection: 'EPSG:9210',   // Bắt buộc khai báo nguồn là VN2000
                    featureProjection: 'EPSG:3857' // Đích là WebMercator
                }) as Feature;

                // Kiểm tra kỹ feature được tạo ra
                if (feature && feature.getGeometry()) {
                    feature.set('tempId', p.tempId);
                    features.push(feature);
                }
            } catch (err) {
                console.warn("Skipping invalid feature:", err);
            }
        });

        if (features.length > 0) {
            vectorSource.current.addFeatures(features);

            // Fit View Safe Check
            try {
                const extent = vectorSource.current.getExtent();
                // Kiểm tra extent hợp lệ (không chứa Infinity)
                if (extent && !isExtentEmpty(extent) && extent.every(isFinite)) {
                    mapInstance.current.getView().fit(extent, { 
                        padding: [50, 50, 50, 50], 
                        duration: 1000 
                    });
                }
            } catch(e) { console.error("Map fit error:", e); }
        }
    }, [parsedData]); // Re-run khi data thay đổi

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setFile(selectedFile);
        setIsParsing(true);
        setError(null);
        setParsedData([]);
        setEditingIndex(null);

        try {
            const reader = new FileReader();
            if (selectedFile.name.toLowerCase().endsWith('.zip')) {
                reader.onload = async (event) => {
                    try {
                        const buffer = event.target?.result as ArrayBuffer;
                        const geojson: any = await shp(buffer);
                        processGeoJSON(Array.isArray(geojson) ? geojson[0] : geojson);
                    } catch (err: any) { setError("Lỗi giải mã Shapefile: " + err.message); }
                    finally { setIsParsing(false); }
                };
                reader.readAsArrayBuffer(selectedFile);
            } else {
                reader.onload = (event) => {
                    try {
                        const text = event.target?.result as string;
                        const content = JSON.parse(text);
                        processGeoJSON(content);
                    } catch (err: any) { setError("File JSON không hợp lệ."); }
                    finally { setIsParsing(false); }
                };
                reader.readAsText(selectedFile);
            }
        } catch (err) { setError("Lỗi hệ thống."); setIsParsing(false); }
    };

    const processGeoJSON = (geojson: any) => {
        // [QUAN TRỌNG] Xóa thuộc tính CRS nếu có để tránh lỗi OpenLayers tự lookup
        if (geojson.crs) delete geojson.crs;

        const features = geojson.features || (geojson.type === 'Feature' ? [geojson] : []);
        if (!features || features.length === 0) {
            setError("Không tìm thấy dữ liệu thửa đất nào.");
            return;
        }

        const results: ParsedParcel[] = features
            .filter((f: any) => f.geometry && f.geometry.coordinates && f.geometry.coordinates.length > 0)
            .map((f: any, index: number) => {
                // Xóa CRS từng feature nếu có
                if (f.crs) delete f.crs;

                const props = f.properties || {};

                const findVal = (keys: string[]) => {
                    for (const k of keys) {
                        const foundKey = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                        if (foundKey && props[foundKey]) return props[foundKey];
                    }
                    return '';
                };

                let areaVal = parseFloat(findVal(['dientich', 'dien_tich', 'shape_area', 'area']));

                return {
                    tempId: `tmp-${Date.now()}-${index}`,
                    sodoto: findVal(['sodoto', 'so_to', 'shbando', 'map_sheet', 'tobando', 'shmap']).toString(),
                    sothua: findVal(['sothua', 'so_thua', 'shthua', 'parcel_no', 'shparcel']).toString(),
                    tenchu: findVal(['tenchu', 'owner', 'ten_chu', 'chusudung']),
                    loaidat: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'mdsd']).toUpperCase(),
                    diachi: findVal(['diachi', 'address', 'location']),
                    dientich: areaVal > 0 ? Math.round(areaVal * 100) / 100 : 0,
                    geometry: f.geometry
                };
            });

        if (results.length === 0) {
            setError("Không tìm thấy đối tượng không gian hợp lệ.");
        } else {
            setParsedData(results);
        }
    };

    const startEditing = (index: number) => {
        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });

        const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === parsedData[index].tempId);
        if (feature) {
            selectInteraction.current?.getFeatures().clear();
            selectInteraction.current?.getFeatures().push(feature);
            // Safe Fit
            const extent = feature.getGeometry()?.getExtent();
            if (extent && extent.every(isFinite)) {
                mapInstance.current?.getView().fit(extent, { padding: [100, 100, 100, 100], duration: 500 });
            }
        }
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);

            const feature = vectorSource.current.getFeatures().find(f => f.get('tempId') === editBuffer.tempId);
            if (feature) {
                feature.setProperties({ ...editBuffer });
            }
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
        selectInteraction.current?.getFeatures().clear();
    };

    const handleImport = async () => {
        const invalidOnes = parsedData.filter(p => !p.sodoto || !p.sothua);
        if (invalidOnes.length > 0) {
            setError(`Còn ${invalidOnes.length} thửa đất thiếu Số Tờ/Số Thửa (màu đỏ). Vui lòng sửa trước khi nạp.`);
            return;
        }

        setImporting(true);
        try {
            await parcelApi.bulkCreate(targetTable, parsedData);
            onSuccess();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally { setImporting(false); }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
            <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-[95vw] h-[90vh] shadow-2xl flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: MAP */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 group flex flex-col">
                        {/* QUAN TRỌNG: Min-height cố định để tránh lỗi 0 height */}
                        <div ref={mapElement} className="flex-1 w-full min-h-[500px]" style={{ width: '100%', height: '100%' }} />

                        <div className="absolute top-4 left-4 z-20 flex flex-col gap-2">
                             <div className="bg-gray-900/80 backdrop-blur-md p-3 rounded-2xl border border-gray-800 shadow-xl pointer-events-none">
                                <h4 className="text-[10px] font-black text-blue-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                                    <MousePointer2 size={12}/> Chế độ tương tác
                                </h4>
                                <p className="text-[9px] text-gray-500 font-bold leading-tight">Nhấp vào thửa đất để sửa thông tin.</p>
                             </div>
                             <button onClick={() => {
                                 // Safe Fit Button
                                 if (vectorSource.current.getFeatures().length > 0) {
                                     const extent = vectorSource.current.getExtent();
                                     if (extent.every(isFinite)) {
                                         mapInstance.current?.getView().fit(extent, { duration: 800, padding: [50,50,50,50] });
                                     }
                                 }
                             }} className="w-10 h-10 bg-gray-900 hover:bg-blue-600 text-white rounded-xl border border-gray-700 flex items-center justify-center transition-all shadow-lg">
                                <Maximize size={18}/>
                             </button>
                        </div>

                        {isParsing && (
                            <div className="absolute inset-0 z-30 bg-gray-950/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
                                <Loader2 className="animate-spin text-blue-500" size={48} />
                                <p className="text-xs font-black text-blue-400 uppercase tracking-[0.3em]">Đang giải mã cấu trúc không gian...</p>
                            </div>
                        )}

                        {!file && (
                            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                                <div className="text-center opacity-10">
                                    <FileUp size={120} className="mx-auto mb-4" />
                                    <p className="text-3xl font-black uppercase tracking-[0.5em]">Tải tệp tin</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* RIGHT PANEL: DATA TABLE */}
                    <div className="w-full lg:w-[500px] flex flex-col bg-gray-900 shrink-0">
                        <div className="p-6 border-b border-gray-800 space-y-6">
                            <div 
                                className={`p-5 rounded-[2rem] border-2 border-dashed transition-all cursor-pointer flex items-center gap-4 ${file ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-gray-800 hover:border-indigo-500/50 bg-gray-950'}`}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                <div className={`p-3 rounded-2xl ${file ? 'bg-emerald-600 text-white' : 'bg-gray-800 text-gray-500'}`}>
                                    <FileUp size={24}/>
                                </div>
                                <div className="flex-1">
                                    <p className="text-[10px] font-black text-white uppercase mb-0.5">{file ? "Thay đổi tệp nguồn" : "Chọn tệp dữ liệu"}</p>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase truncate max-w-[200px]">{file ? file.name : "ZIP (SHP) hoặc GEOJSON"}</p>
                                </div>
                                <input ref={fileInputRef} type="file" className="hidden" accept=".zip,.geojson,.json" onChange={handleFileChange} />
                            </div>

                            {parsedData.length > 0 && (
                                <div className="flex gap-4">
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Tổng số</p>
                                        <p className="text-lg font-black text-white">{parsedData.length}</p>
                                    </div>
                                    <div className="flex-1 bg-gray-950 p-3 rounded-2xl border border-gray-800">
                                        <p className="text-[8px] text-gray-500 font-black uppercase mb-1">Hợp lệ</p>
                                        <p className="text-lg font-black text-emerald-500">{parsedData.filter(p=>p.sodoto && p.sothua).length}</p>
                                    </div>
                                </div>
                            )}

                            {error && (
                                <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl flex items-start gap-3 animate-in shake duration-300">
                                    <AlertTriangle className="text-red-500 shrink-0" size={18}/>
                                    <p className="text-[10px] text-red-400 font-black leading-tight uppercase tracking-tighter">{error}</p>
                                </div>
                            )}
                        </div>

                        <div className="flex-1 overflow-hidden flex flex-col">
                            <div className="flex-1 overflow-auto custom-scrollbar bg-gray-950/20">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-gray-950 text-gray-600 uppercase text-[9px] font-black tracking-widest sticky top-0 z-10 border-b border-gray-800">
                                        <tr>
                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin</th>
                                            <th className="p-4 w-16"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${isEditing ? 'bg-orange-600/10' : isInvalid ? 'bg-red-600/5' : 'hover:bg-indigo-600/5'}`}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="flex gap-1">
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sodoto} onChange={e=>setEditBuffer({...editBuffer!, sodoto: e.target.value})} placeholder="Tờ" />
                                                                <input className="w-full bg-gray-950 border border-orange-500/50 rounded px-2 py-1.5 text-[11px] text-white font-black" value={editBuffer?.sothua} onChange={e=>setEditBuffer({...editBuffer!, sothua: e.target.value})} placeholder="Thửa" />
                                                            </div>
                                                        ) : (
                                                            <span className={`font-black text-sm ${isInvalid ? 'text-red-500' : 'text-blue-400'}`}>
                                                                {p.sodoto || '?'}/{p.sothua || '?'}
                                                            </span>
                                                        )}
                                                    </td>
                                                    <td className="p-2">
                                                        {isEditing ? (
                                                            <div className="space-y-1.5">
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-white" value={editBuffer?.tenchu || ''} onChange={e=>setEditBuffer({...editBuffer!, tenchu: e.target.value})} placeholder="Chủ sử dụng" />
                                                                <input className="w-full bg-gray-950 border border-slate-700 rounded px-2 py-1 text-[10px] text-blue-300 font-bold uppercase" value={editBuffer?.loaidat || ''} onChange={e=>setEditBuffer({...editBuffer!, loaidat: e.target.value.toUpperCase()})} placeholder="Loại đất" />
                                                            </div>
                                                        ) : (
                                                            <div className="space-y-1">
                                                                <p className="text-[11px] font-bold text-gray-300 truncate max-w-[150px]">{p.tenchu || <span className="italic opacity-30">Chưa nhập tên</span>}</p>
                                                                <span className="text-[9px] font-black text-slate-500 uppercase px-1.5 py-0.5 bg-gray-900 rounded border border-gray-800">{p.loaidat || '--'}</span>
                                                            </div>
                                                        )}
                                                    </td>
                                                    <td className="p-2 text-right">
                                                        {isEditing ? (
                                                            <div className="flex gap-1 justify-end">
                                                                <button onClick={saveRow} className="p-1.5 bg-emerald-600 text-white rounded hover:bg-emerald-500"><Check size={14}/></button>
