        setEditingIndex(index);
        setEditBuffer({ ...parsedData[index] });
    };

    const saveRow = () => {
        if (editingIndex !== null && editBuffer) {
            const newData = [...parsedData];
            newData[editingIndex] = editBuffer;
            setParsedData(newData);
            setEditingIndex(null);
            setEditBuffer(null);
        }
    };

    const cancelEditing = () => {
        setEditingIndex(null);
        setEditBuffer(null);
    };

