                {/* Header */}
                <div className="p-5 border-b border-gray-800 flex justify-between items-center bg-gray-950/50 shrink-0">
                    <div className="flex items-center gap-4">
                        <div className="bg-indigo-600/20 p-2.5 rounded-2xl border border-indigo-500/30">
                            <Layers className="text-indigo-400" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-black uppercase text-white leading-none mb-1">Kiểm soát dữ liệu nhập tệp</h3>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Database size={10}/> PostGIS: {targetTable}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
                    {/* LEFT PANEL: SUMMARY STATUS (Thay thế Map) */}
                    <div className="flex-1 bg-gray-950 relative border-r border-gray-800 flex flex-col items-center justify-center p-8 text-center gap-6">

                        {isParsing ? (
                            <div className="flex flex-col items-center gap-4 animate-in fade-in">
                                <Loader2 className="animate-spin text-blue-500" size={64} />
                                <div>
                                    <p className="text-sm font-black text-blue-400 uppercase tracking-widest">Đang phân tích cấu trúc...</p>
                                    <p className="text-xs text-gray-500 mt-1">Vui lòng chờ trong giây lát</p>
                                </div>
                            </div>
                        ) : !file ? (
                            <div className="flex flex-col items-center gap-4 opacity-40 animate-in zoom-in duration-300">
                                <div className="w-32 h-32 rounded-full bg-gray-900 border-4 border-gray-800 flex items-center justify-center border-dashed">
                                    <FileUp size={48} className="text-gray-600"/>
                                </div>
                                <div>
                                    <p className="text-lg font-black text-gray-400 uppercase tracking-widest">Chưa có tệp tin</p>
                                    <p className="text-xs text-gray-600 mt-1">Chọn file .ZIP (Shapefile) hoặc .GEOJSON bên phải để bắt đầu</p>
                                </div>
                            </div>
                        ) : parsedData.length > 0 ? (
                            <div className="w-full max-w-sm space-y-6 animate-in slide-in-from-bottom-4 duration-500">
                                <div className="flex items-center gap-4 bg-gray-900 p-4 rounded-2xl border border-gray-800">
                                    <div className="bg-emerald-500/10 p-3 rounded-xl">
                                        <FileJson size={24} className="text-emerald-500"/>
                                    </div>
                                    <div className="text-left overflow-hidden">
                                        <p className="text-xs font-bold text-white truncate">{file.name}</p>
                                        <p className="text-[10px] text-gray-500 font-mono">{(file.size/1024).toFixed(1)} KB</p>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800 flex flex-col items-center">
