                                        <span className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Tổng số</span>
                                    </div>
                                    <div className="bg-gray-900 p-4 rounded-2xl border border-gray-800 flex flex-col items-center">
                                        <span className={`text-2xl font-black ${invalidCount > 0 ? 'text-red-500' : 'text-emerald-500'}`}>
