                                            <th className="p-4 w-12 text-center">STT</th>
                                            <th className="p-4 w-28">Số tờ/thửa</th>
                                            <th className="p-4">Thông tin</th>
                                            <th className="p-4 w-16"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-800/50">
                                        {parsedData.map((p, i) => {
                                            const isEditing = editingIndex === i;
                                            const isInvalid = !p.sodoto || !p.sothua;
                                            const isHovered = hoveredIndex === i;

                                            return (
                                                <tr 
                                                    key={p.tempId} 
                                                    id={`row-${p.tempId}`}
                                                    className={`transition-all ${
                                                        isEditing ? 'bg-orange-600/10 border-l-4 border-orange-500' : 
                                                        isHovered ? 'bg-blue-600/10 border-l-4 border-blue-500' : 
                                                        isInvalid ? 'bg-red-600/5' : 'hover:bg-gray-800'
