                                                    onMouseEnter={() => setHoveredIndex(i)}
                                                    onMouseLeave={() => setHoveredIndex(null)}
                                                >
                                                    <td className="p-4 text-center text-gray-700 font-mono text-[10px]">{i + 1}</td>
                                                    <td className="p-2">
