                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useState, useEffect, Suspense, lazy } from 'react';
import { Routes, Route, useNavigate, useLocation, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import { User, UserRole, SystemSetting } from './types';
import { ShieldAlert, RefreshCw, WifiOff } from 'lucide-react';
import { adminService, authService } from './services/mockBackend';

// Lazy Load các trang để tối ưu tốc độ tải bundle ban đầu
const MapPage = lazy(() => import('./pages/MapPage'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const AdminPage = lazy(() => import('./pages/AdminPage'));
const UserProfile = lazy(() => import('./pages/UserProfile'));
const Messaging = lazy(() => import('./pages/Messaging'));
const QRGenerator = lazy(() => import('./components/tools/QRGenerator'));
const EditorPage = lazy(() => import('./pages/EditorPage'));
const LandPriceLookup = lazy(() => import('./pages/LandPriceLookup'));

const PageLoader = () => (
    <div className="h-full w-full bg-slate-900/50 backdrop-blur-sm flex flex-col items-center justify-center text-white gap-4 animate-in fade-in duration-300">
        <div className="relative">
            <RefreshCw className="animate-spin text-blue-500" size={40} />
            <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
            </div>
        </div>
        <p className="font-display uppercase tracking-[0.3em] text-[9px] text-blue-400 font-black animate-pulse">
            Đang nạp Module hệ thống...
        </p>
    </div>
);

// Bản đồ ánh xạ giữa ID Menu và URL Path
const PATH_MAPPING: Record<string, string> = {
    'map': '/',
    'dashboard': '/dashboard',
    'editor': '/editor',
    'profile': '/profile',
    'messaging': '/messages',
    'qr-generator': '/tools/qr',
    'land-price': '/land-price',
    'admin': '/admin'
};

// Bản đồ ngược để highlight Sidebar dựa trên URL
const REVERSE_PATH_MAPPING: Record<string, string> = Object.entries(PATH_MAPPING).reduce((acc, [key, value]) => {
    acc[value] = key;
    return acc;
}, {} as Record<string, string>);

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [verificationToken, setVerificationToken] = useState<string | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [bootError, setBootError] = useState<string | null>(null);

  const navigate = useNavigate();
  const location = useLocation();

  // Xác định activePage cho Sidebar dựa trên URL hiện tại
  const currentPath = location.pathname === '/' ? '/' : `/${location.pathname.split('/')[1]}`;
  const activePage = REVERSE_PATH_MAPPING[currentPath] || 
                     (location.pathname.startsWith('/admin') ? 'admin' : 
                     (location.pathname.startsWith('/tools/qr') ? 'qr-generator' : 'map'));

  const boot = async () => {
      setLoading(true);
      setBootError(null);

      const timeoutPromise = new Promise((_, reject) => 
          setTimeout(() => reject(new Error("Server không phản hồi kịp lúc (Timeout)")), 12000)
      );

      try {
          const loadDataPromise = (async () => {
              const settings: SystemSetting[] = await adminService.getSettings();
              const settingsMap: Record<string, string> = {};
              settings.forEach(s => settingsMap[s.key] = s.value);

              const savedUser = localStorage.getItem('geo_user');
              if (savedUser) {
                  const localUser = JSON.parse(savedUser);
                  try {
                      const freshUser = await authService.getProfile(localUser.id);
                      if (freshUser) return { settingsMap, user: { ...localUser, ...freshUser } };
                  } catch (e) { return { settingsMap, user: localUser }; }
              }
              return { settingsMap, user: null };
          })();

          const result: any = await Promise.race([loadDataPromise, timeoutPromise]);

          setSystemSettings(result.settingsMap);
          if (result.user) {
              setUser(result.user);
              localStorage.setItem('geo_user', JSON.stringify(result.user));
          }

          if (result.settingsMap['system_name']) document.title = result.settingsMap['system_name'];

          if (result.settingsMap['site_favicon']) {
              const favicon = document.getElementById('favicon') as HTMLLinkElement;
              if (favicon) {
                  favicon.href = result.settingsMap['site_favicon'];
              }
          }
      } catch (e: any) {
          console.error("Khởi động thất bại:", e.message);
          setBootError(e.message || "Không thể kết nối đến máy chủ API.");
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      if (params.get('token')) { setResetToken(params.get('token')); setShowLogin(true); }
      if (params.get('verificationToken')) { setVerificationToken(params.get('verificationToken')); setShowLogin(true); }
      boot();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
    setResetToken(null);
    setVerificationToken(null);
    // Điều hướng dựa trên role sau khi login
    navigate(loggedInUser.role === UserRole.ADMIN ? '/admin' : '/dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    navigate('/');
  };

  const handleNavigate = (pageId: string) => {
      const path = PATH_MAPPING[pageId];
      if (path) {
          navigate(path);
      }
  };

  // Protected Route Wrapper
  const ProtectedRoute = ({ children, requiredRole }: { children?: React.ReactNode, requiredRole?: UserRole }) => {
      if (!user) return <Navigate to="/" replace />;
      if (requiredRole && user.role !== requiredRole && user.role !== UserRole.ADMIN) {
          return <Navigate to="/" replace />;
      }
      return <>{children}</>;
  };

  if (bootError) return (
      <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
          <div className="w-20 h-20 bg-red-500/20 rounded-full flex items-center justify-center mb-6 border border-red-500/30">
              <WifiOff className="text-red-500" size={40} />
          </div>
          <h1 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Cảnh báo hệ thống</h1>
          <p className="text-slate-400 max-w-md text-sm mb-8 leading-relaxed">
              {bootError === "Server không phản hồi kịp lúc (Timeout)" 
                ? "Máy chủ đang gặp tình trạng quá tải hoặc kết nối Internet của bạn không ổn định." 
                : bootError}
          </p>
          <button 
            onClick={boot}
            className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-900/20 transition-all active:scale-95 flex items-center gap-2"
          >
              <RefreshCw size={16}/> Thử kết nối lại
          </button>
      </div>
  );

  if (loading) return (
      <div className="h-screen w-full bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
          <div className="relative">
              <RefreshCw className="animate-spin text-blue-500" size={48} />
              <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-2 h-2 bg-white rounded-full animate-ping"></div>
              </div>
          </div>
          <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
      </div>
  );

  if (showLogin) return (
      <Login 
        onLogin={handleLogin} 
        onCancel={() => { setShowLogin(false); setResetToken(null); setVerificationToken(null); }}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        footerText={systemSettings['footer_text']}
        allowRegistration={systemSettings['allow_registration'] === 'true'}
        initialToken={resetToken}
        verificationToken={verificationToken}
      />
  );

  if (systemSettings['maintenance_mode'] === 'true' && user?.role !== UserRole.ADMIN) return (
      <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
          <ShieldAlert className="text-orange-500 mb-6" size={64} />
          <h1 className="text-3xl font-display font-bold text-white mb-2 uppercase tracking-tighter">Hệ thống bảo trì</h1>
          <p className="text-slate-500 text-sm">Chúng tôi đang nâng cấp hệ thống để phục vụ tốt hơn.</p>
          <button onClick={() => setShowLogin(true)} className="text-blue-500 hover:underline mt-8 font-bold text-xs uppercase tracking-widest">Dành cho Quản trị viên</button>
      </div>
  );

  return (
    <div className="flex h-screen w-full bg-gray-900 overflow-hidden font-sans relative">
      <Sidebar 
        user={user} 
        activePage={activePage} 
        onNavigate={handleNavigate} 
        onLogout={handleLogout}
        onLoginClick={() => setShowLogin(true)}
        onCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        isCollapsed={isSidebarCollapsed}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
      />
      <main className="flex-1 h-full relative overflow-hidden bg-gray-100 flex flex-col transition-all">
        <Suspense fallback={<PageLoader />}>
            <Routes>
                <Route path="/" element={<MapPage user={user} systemSettings={systemSettings} />} />
                <Route path="/land-price" element={<LandPriceLookup />} />
                <Route path="/tools/qr" element={<QRGenerator />} />

                {/* Protected Routes */}
                <Route path="/dashboard" element={<ProtectedRoute><Dashboard user={user!} /></ProtectedRoute>} />
                <Route path="/editor" element={<ProtectedRoute><EditorPage user={user!} /></ProtectedRoute>} />
                <Route path="/profile" element={<ProtectedRoute><UserProfile user={user!} onUpdateUser={u => { setUser(u); localStorage.setItem('geo_user', JSON.stringify(u)); }} /></ProtectedRoute>} />
                <Route path="/messages" element={<ProtectedRoute><Messaging user={user!} /></ProtectedRoute>} />

                {/* Admin Route */}
                <Route path="/admin" element={
                    <ProtectedRoute requiredRole={UserRole.ADMIN}>
                        <AdminPage systemName={systemSettings['system_name']} logoUrl={systemSettings['site_logo']} />
                    </ProtectedRoute>
                } />

                {/* Fallback */}
                <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
        </Suspense>
      </main>
    </div>
  );
};

export default App;

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng và SRID (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tìm tên cột và SRID hiện tại của bảng
     */
    const resolveTableColumns = async (tableName) => {
        if (SCHEMA_CACHE.has(tableName)) {
            return SCHEMA_CACHE.get(tableName);
        }

        try {
            // Lấy danh sách cột
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            // Lấy SRID hiện tại của cột geometry
            const sridRes = await pool.query(`
                SELECT srid FROM geometry_columns 
                WHERE f_table_name = $1 AND f_geometry_column = 'geometry'
                LIMIT 1
            `, [tableName]);

            const currentSrid = sridRes.rows[0]?.srid || 4326;

            const dbColsMap = {};
            res.rows.forEach(r => {
                dbColsMap[r.column_name.toLowerCase()] = r.column_name;
            });

            const mapping = { _srid: currentSrid };
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) {
                    if (dbColsMap[candidate]) {
                        foundCol = dbColsMap[candidate];
                        break;
                    }
                }
                mapping[standardKey] = foundCol;
            }

            SCHEMA_CACHE.set(tableName, mapping);
            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich', _srid: 4326 };
        }
    };

    const syncTableSchema = async (tableName) => {
        try {
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            // 1. Kiểm tra thiếu cột thuộc tính
            const missingCols = [];
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });

            if (missingCols.length > 0) {
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
            }

            // 2. Tự động sửa SRID 4326 -> 9210 nếu cần
            if (currentMap._srid !== 9210) {
                try {
                    await pool.query(`
                        ALTER TABLE "${tableName}" 
                        ALTER COLUMN geometry TYPE geometry(Geometry, 9210) 
                        USING ST_SetSRID(geometry, 9210)
                    `);
                    console.log(`[Migrate] Forced SRID 9210 for table: ${tableName}`);
                } catch (err) {
                    console.warn(`[Migrate Skip] Could not force SRID 9210 for ${tableName}, using dynamic SRID instead.`);
                }
            }

            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
            SCHEMA_CACHE.delete(tableName); 
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 9210),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/rename', async (req, res) => {
        const { oldName, newName, displayName, description } = req.body;
        try {
            await pool.query('BEGIN');
            // Nếu tên bảng vật lý thay đổi, thực hiện ALTER TABLE
            if (oldName !== newName) {
                await pool.query(`ALTER TABLE "${oldName}" RENAME TO "${newName}"`);
            }
            // Cập nhật Registry
            await pool.query(`
                UPDATE spatial_tables_registry 
                SET table_name = $1, display_name = $2, description = $3 
                WHERE table_name = $4
            `, [newName, displayName, description, oldName]);

            await pool.query('COMMIT');
            SCHEMA_CACHE.delete(oldName);
            SCHEMA_CACHE.delete(newName);
            res.json({ status: 'ok' });
        } catch (e) {
            await pool.query('ROLLBACK');
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        const { tableName } = req.body;
        try {
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            SCHEMA_CACHE.delete(tableName);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        try {
            const cols = await resolveTableColumns(table);
            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;

            // FIX: Chuyển từ ILIKE '%...%' sang so khớp chính xác '='
            if (sodoto) { 
                query += ` AND "${cols.sodoto}"::text = $${idx++}`; 
                params.push(sodoto); 
            }
            if (sothua) { 
                query += ` AND "${cols.sothua}"::text = $${idx++}`; 
                params.push(sothua); 
            }
            // Với tên chủ và địa chỉ, sử dụng ILIKE (không phân biệt hoa thường) nhưng KHÔNG dùng '%' để tìm chính xác
            if (tenchu) { 
                query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; 
                params.push(tenchu); 
            }
            if (diachi) { 
                query += ` AND "${cols.diachi}" ILIKE $${idx++}`; 
                params.push(diachi); 
            }

            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            res.json(result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null
            })));
        } catch (e) {
            SCHEMA_CACHE.delete(table);
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
            }
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    /**
     * Endpoint NẠP HÀNG LOẠT (BULK INSERT)
     */
    router.post('/data/:table/bulk', async (req, res) => {
        const { table } = req.params;
        const { items } = req.body; // Mảng các thửa đất [{sodoto, sothua, ...}]
        if (!Array.isArray(items) || items.length === 0) return res.status(400).json({ error: "Dữ liệu không hợp lệ." });

        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            await pool.query('BEGIN');

            for (const item of items) {
                let geomSql = 'NULL';
                const params = [item.sodoto, item.sothua, item.tenchu, item.diachi, item.loaidat, item.dientich];
                if (item.geometry) {
                    geomSql = `ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid}))`;
                    params.push(JSON.stringify(item.geometry));
                }
                const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql})`;
                await pool.query(query, params);
            }

            await pool.query('COMMIT');
            await logSystemAction(req, 'BULK_IMPORT', `Nạp hàng loạt ${items.length} thửa đất vào bảng ${table}`);
            res.json({ status: 'ok', count: items.length });
        } catch (e) {
            await pool.query('ROLLBACK');
            res.status(500).json({ error: e.message });
        }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;

            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($${idx}), ${targetSrid}))`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 
        if (!file) return res.status(400).json({ error: 'No file uploaded' });
        try {
            const cols = await resolveTableColumns(table);
            const targetSrid = cols._srid || 4326;
            const buffer = fs.readFileSync(file.path);
            let geojson;
            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());
            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;
            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");

            if (gid) {
                await pool.query(`UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})) WHERE gid=$8`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]);
            } else {
                await pool.query(`INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_Multi(ST_SetSRID(ST_GeomFromGeoJSON($7), ${targetSrid})))`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]);
            }
            fs.unlinkSync(file.path);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

