        if (subTab === 'BACKUP') {
            loadBackupTables();
        }
    }, [subTab]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [data, info] = await Promise.all([
                adminService.getSettings(),
                adminService.getServerInfo().catch(() => null)
            ]);
            setSettings(data);
            setServerInfo(info);
        } catch (e) { 
            console.error(e); 
        } finally {
            setLoading(false);
        }
    };

