import React, { useEffect } from 'react';

interface SeoProps {
    title: string;
    description?: string;
    keywords?: string;
    systemSettings?: Record<string, string>;
}

const Seo: React.FC<SeoProps> = ({ title, description, keywords, systemSettings }) => {
    useEffect(() => {
        // Tên hệ thống / Suffix tiêu đề
        const siteName = systemSettings?.system_name || "GeoMaster";
        const seoTitleSuffix = systemSettings?.seo_title || siteName;

        // Cập nhật Title
        document.title = `${title} | ${seoTitleSuffix}`;

        // Cập nhật Meta Description
        const finalDesc = description || systemSettings?.seo_description || "Hệ thống WebGIS GeoMaster - Tra cứu quy hoạch và quản lý đất đai chuyên nghiệp.";
        let metaDesc = document.querySelector('meta[name="description"]');
        if (!metaDesc) {
            metaDesc = document.createElement('meta');
            metaDesc.setAttribute('name', "description");
            document.head.appendChild(metaDesc);
        }
        metaDesc.setAttribute('content', finalDesc);

        // Cập nhật Keywords
        const finalKeywords = keywords || systemSettings?.seo_keywords || "webgis, quy hoạch, giá đất, postgis, bản đồ số";
        let metaKeys = document.querySelector('meta[name="keywords"]');
        if (!metaKeys) {
            metaKeys = document.createElement('meta');
            metaKeys.setAttribute('name', "keywords");
            document.head.appendChild(metaKeys);
        }
        metaKeys.setAttribute('content', finalKeywords);

        // Cập nhật Open Graph (Mạng xã hội)
        let ogTitle = document.querySelector('meta[property="og:title"]');
        if (!ogTitle) { ogTitle = document.createElement('meta'); ogTitle.setAttribute('property', "og:title"); document.head.appendChild(ogTitle); }
        ogTitle.setAttribute('content', document.title);

        let ogDesc = document.querySelector('meta[property="og:description"]');
        if (!ogDesc) { ogDesc = document.createElement('meta'); ogDesc.setAttribute('property', "og:description"); document.head.appendChild(ogDesc); }
        ogDesc.setAttribute('content', finalDesc);

        if (systemSettings?.seo_og_image) {
            let ogImg = document.querySelector('meta[property="og:image"]');
            if (!ogImg) { ogImg = document.createElement('meta'); ogImg.setAttribute('property', "og:image"); document.head.appendChild(ogImg); }
            ogImg.setAttribute('content', systemSettings.seo_og_image);
        }

        // Cập nhật Favicon động
        if (systemSettings?.site_favicon) {
            let favicon = document.getElementById('favicon') as HTMLLinkElement;
            if (!favicon) {
                favicon = document.createElement('link');
                favicon.id = 'favicon';
                favicon.rel = 'icon';
                document.head.appendChild(favicon);
            }
            favicon.href = systemSettings.site_favicon;
        }

    }, [title, description, keywords, systemSettings]);

    return null;
};

export default Seo;

import React, { useState, useEffect, Suspense, lazy } from 'react';
import { Routes, Route, useNavigate, useLocation, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import { User, UserRole, SystemSetting } from './types';
import { ShieldAlert, RefreshCw, WifiOff } from 'lucide-react';
import { adminService, authService } from './services/mockBackend';

// Lazy Load các trang để tối ưu tốc độ tải bundle ban đầu
const MapPage = lazy(() => import('./pages/MapPage'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const AdminPage = lazy(() => import('./pages/AdminPage'));
const UserProfile = lazy(() => import('./pages/UserProfile'));
const Messaging = lazy(() => import('./pages/Messaging'));
const QRGenerator = lazy(() => import('./components/tools/QRGenerator'));
const EditorPage = lazy(() => import('./pages/EditorPage'));
const LandPriceLookup = lazy(() => import('./pages/LandPriceLookup'));

const PageLoader = () => (
    <div className="h-full w-full bg-slate-900/50 backdrop-blur-sm flex flex-col items-center justify-center text-white gap-4 animate-in fade-in duration-300">
        <div className="relative">
            <RefreshCw className="animate-spin text-blue-500" size={40} />
            <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
            </div>
        </div>
        <p className="font-display uppercase tracking-[0.3em] text-[9px] text-blue-400 font-black animate-pulse">
            Đang nạp Module hệ thống...
        </p>
    </div>
);

// Bản đồ ánh xạ giữa ID Menu và URL Path
const PATH_MAPPING: Record<string, string> = {
    'map': '/',
    'dashboard': '/dashboard',
    'editor': '/editor',
    'profile': '/profile',
    'messaging': '/messages',
    'qr-generator': '/tools/qr',
    'land-price': '/land-price',
    'admin': '/admin'
};

// Bản đồ ngược để highlight Sidebar dựa trên URL
const REVERSE_PATH_MAPPING: Record<string, string> = Object.entries(PATH_MAPPING).reduce((acc, [key, value]) => {
    acc[value] = key;
    return acc;
}, {} as Record<string, string>);

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [verificationToken, setVerificationToken] = useState<string | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [bootError, setBootError] = useState<string | null>(null);

  // Theme State: 'dark' | 'light'
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
      return (localStorage.getItem('geo_theme') as 'dark' | 'light') || 'dark';
  });

  const navigate = useNavigate();
  const location = useLocation();

  // Xác định activePage cho Sidebar dựa trên URL hiện tại
  const currentPath = location.pathname === '/' ? '/' : `/${location.pathname.split('/')[1]}`;
  const activePage = REVERSE_PATH_MAPPING[currentPath] || 
                     (location.pathname.startsWith('/admin') ? 'admin' : 
                     (location.pathname.startsWith('/tools/qr') ? 'qr-generator' : 'map'));

  const toggleTheme = () => {
      const newTheme = theme === 'dark' ? 'light' : 'dark';
      setTheme(newTheme);
      localStorage.setItem('geo_theme', newTheme);
  };

  const boot = async () => {
      setLoading(true);
      setBootError(null);

      const timeoutPromise = new Promise((_, reject) => 
          setTimeout(() => reject(new Error("Server không phản hồi kịp lúc (Timeout)")), 12000)
      );

      try {
          const loadDataPromise = (async () => {
              const settings: SystemSetting[] = await adminService.getSettings();
              const settingsMap: Record<string, string> = {};
              settings.forEach(s => settingsMap[s.key] = s.value);

              const savedUser = localStorage.getItem('geo_user');
              if (savedUser) {
                  const localUser = JSON.parse(savedUser);
                  try {
                      const freshUser = await authService.getProfile(localUser.id);
                      if (freshUser) return { settingsMap, user: { ...localUser, ...freshUser } };
                  } catch (e) { return { settingsMap, user: localUser }; }
              }
              return { settingsMap, user: null };
          })();

          const result: any = await Promise.race([loadDataPromise, timeoutPromise]);

          setSystemSettings(result.settingsMap);
          if (result.user) {
              setUser(result.user);
              localStorage.setItem('geo_user', JSON.stringify(result.user));
          }

          if (result.settingsMap['system_name']) document.title = result.settingsMap['system_name'];

          if (result.settingsMap['site_favicon']) {
              const favicon = document.getElementById('favicon') as HTMLLinkElement;
              if (favicon) {
                  favicon.href = result.settingsMap['site_favicon'];
              }
          }
      } catch (e: any) {
          console.error("Khởi động thất bại:", e.message);
          setBootError(e.message || "Không thể kết nối đến máy chủ API.");
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      if (params.get('token')) { setResetToken(params.get('token')); setShowLogin(true); }
      if (params.get('verificationToken')) { setVerificationToken(params.get('verificationToken')); setShowLogin(true); }
      boot();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
    setResetToken(null);
    setVerificationToken(null);
    navigate(loggedInUser.role === UserRole.ADMIN ? '/admin' : '/dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    navigate('/');
  };

  const handleNavigate = (pageId: string) => {
      const path = PATH_MAPPING[pageId];
      if (path) {
          navigate(path);
      }
  };

  // Protected Route Wrapper
  const ProtectedRoute = ({ children, requiredRole }: { children?: React.ReactNode, requiredRole?: UserRole }) => {
      if (!user) return <Navigate to="/" replace />;
      if (requiredRole && user.role !== requiredRole && user.role !== UserRole.ADMIN) {
          return <Navigate to="/" replace />;
      }
      return <>{children}</>;
  };

  if (bootError) return (
      <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
          <div className="w-20 h-20 bg-red-500/20 rounded-full flex items-center justify-center mb-6 border border-red-500/30">
              <WifiOff className="text-red-500" size={40} />
          </div>
          <h1 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Cảnh báo hệ thống</h1>
          <p className="text-slate-400 max-w-md text-sm mb-8 leading-relaxed">
              {bootError === "Server không phản hồi kịp lúc (Timeout)" 
                ? "Máy chủ đang gặp tình trạng quá tải hoặc kết nối Internet của bạn không ổn định." 
                : bootError}
          </p>
          <button 
            onClick={boot}
            className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-900/20 transition-all active:scale-95 flex items-center gap-2"
          >
              <RefreshCw size={16}/> Thử kết nối lại
          </button>
      </div>
  );

  if (loading) return (
      <div className="h-screen w-full bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
          <div className="relative">
              <RefreshCw className="animate-spin text-blue-500" size={48} />
              <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-2 h-2 bg-white rounded-full animate-ping"></div>
              </div>
          </div>
          <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
      </div>
  );

  if (showLogin) return (
      <Login 
        onLogin={handleLogin} 
        onCancel={() => { setShowLogin(false); setResetToken(null); setVerificationToken(null); }}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        footerText={systemSettings['footer_text']}
        allowRegistration={systemSettings['allow_registration'] === 'true'}
        initialToken={resetToken}
        verificationToken={verificationToken}
      />
  );

  if (systemSettings['maintenance_mode'] === 'true' && user?.role !== UserRole.ADMIN) return (
      <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
          <ShieldAlert className="text-orange-500 mb-6" size={64} />
          <h1 className="text-3xl font-display font-bold text-white mb-2 uppercase tracking-tighter">Hệ thống bảo trì</h1>
          <p className="text-slate-500 text-sm">Chúng tôi đang nâng cấp hệ thống để phục vụ tốt hơn.</p>
          <button onClick={() => setShowLogin(true)} className="text-blue-500 hover:underline mt-8 font-bold text-xs uppercase tracking-widest">Dành cho Quản trị viên</button>
      </div>
  );

  return (
    <div className={`flex h-screen w-full overflow-hidden font-sans relative transition-colors duration-300 ${theme === 'light' ? 'bg-slate-50' : 'bg-gray-900'}`}>
      <Sidebar 
        user={user} 
        activePage={activePage} 
        onNavigate={handleNavigate} 
        onLogout={handleLogout}
        onLoginClick={() => setShowLogin(true)}
        onCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        isCollapsed={isSidebarCollapsed}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        theme={theme}
        onToggleTheme={toggleTheme}
      />
      <main className={`flex-1 h-full relative overflow-hidden flex flex-col transition-all ${theme === 'light' ? 'bg-slate-100' : 'bg-gray-950'}`}>
        <Suspense fallback={<PageLoader />}>
            <Routes>
                <Route path="/" element={<MapPage user={user} systemSettings={systemSettings} />} />
                <Route path="/land-price" element={<LandPriceLookup />} />
                <Route path="/tools/qr" element={<QRGenerator />} />

                {/* Protected Routes - Passing Theme Props where needed */}
                <Route path="/dashboard" element={<ProtectedRoute><Dashboard user={user!} theme={theme} /></ProtectedRoute>} />
                <Route path="/editor" element={<ProtectedRoute><EditorPage user={user!} /></ProtectedRoute>} />
                <Route path="/profile" element={<ProtectedRoute><UserProfile user={user!} onUpdateUser={u => { setUser(u); localStorage.setItem('geo_user', JSON.stringify(u)); }} /></ProtectedRoute>} />
                <Route path="/messages" element={<ProtectedRoute><Messaging user={user!} /></ProtectedRoute>} />

                {/* Admin Route */}
                <Route path="/admin" element={
                    <ProtectedRoute requiredRole={UserRole.ADMIN}>
                        <AdminPage systemName={systemSettings['system_name']} logoUrl={systemSettings['site_logo']} />
                    </ProtectedRoute>
                } />

                {/* Fallback */}
                <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
        </Suspense>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, UserRole, MenuItem, SystemNotification } from '../types';
import { LogOut, LogIn, ChevronLeft, ChevronRight, User as UserIcon, Database, HelpCircle, ExternalLink, Bell, X, Info, AlertTriangle, Clock, Mail, Sun, Moon } from 'lucide-react';
import * as Icons from 'lucide-react';
import { adminService, notificationService, API_URL } from '../services/mockBackend';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
  theme: 'dark' | 'light';
  onToggleTheme: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    user, 
    activePage, 
    onNavigate, 
    onLogout, 
    onLoginClick, 
    onCollapse, 
    isCollapsed,
    systemName, 
    logoUrl,
    theme,
    onToggleTheme
}) => {
  const [dynamicMenu, setDynamicMenu] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [imgError, setImgError] = useState(false);

  // Notification States
  const [notifications, setNotifications] = useState<SystemNotification[]>([]);
  const [isNotiOpen, setIsNotiOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const notiRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      setImgError(false);
  }, [user?.avatar]);

  useEffect(() => {
      const fetchMenu = async () => {
          try {
              if (adminService && typeof adminService.getMenuItems === 'function') {
                  const items = await adminService.getMenuItems();
                  setDynamicMenu(items.filter(i => i.is_active).sort((a, b) => a.order_index - b.order_index));
              }
          } catch (e) {
              console.error("Failed to load sidebar menu", e);
          } finally {
              setLoading(false);
          }
      };
      fetchMenu();
  }, [user?.role]);

  // Fetch Notifications
  useEffect(() => {
      if (user) {
          const fetchNoti = async () => {
              try {
                  const data = await notificationService.getNotifications();
                  setNotifications(data);
                  const lastRead = localStorage.getItem(`last_read_noti_${user.id}`) || '0';
                  const count = data.filter(n => new Date(n.created_at).getTime() > parseInt(lastRead)).length;
                  setUnreadCount(count);
              } catch (e) {}
          };
          fetchNoti();
          const interval = setInterval(fetchNoti, 60000);
          return () => clearInterval(interval);
      }
  }, [user]);

  useEffect(() => {
      const handleOutside = (e: MouseEvent) => {
          if (notiRef.current && !notiRef.current.contains(e.target as Node)) setIsNotiOpen(false);
      };
      document.addEventListener('mousedown', handleOutside);
      return () => document.removeEventListener('mousedown', handleOutside);
  }, []);

  const handleOpenNoti = () => {
      setIsNotiOpen(!isNotiOpen);
      if (!isNotiOpen && user) {
          setUnreadCount(0);
          localStorage.setItem(`last_read_noti_${user.id}`, Date.now().toString());
      }
  };

  const visibleItems = dynamicMenu.filter(item => {
    if (!user) return item.roles.includes('GUEST');
    return item.roles.includes(user.role);
  });

  const handleMenuClick = (item: MenuItem) => {
      if (item.type === 'EXTERNAL' && item.url) {
          window.open(item.url, '_blank');
      } else {
          onNavigate(item.id);
      }
  };

  const getAvatarUrl = (path?: string) => {
      if (!path) return null;
      if (path.startsWith('http') || path.startsWith('data:')) return path;
      const cleanPath = path.startsWith('/') ? path : `/${path}`;
      const baseUrl = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;
      return `${baseUrl}${cleanPath}?cache_bust=${new Date().getTime()}`;
  };

  const renderAvatar = () => {
      if (!user) return <UserIcon size={18} className="text-blue-400" />;
      const avatarSrc = getAvatarUrl(user.avatar);
      if (avatarSrc && !imgError) {
          return <img src={avatarSrc} alt={user.name} className="w-full h-full object-cover" onError={() => setImgError(true)} />;
      }
      return (
          <div className="w-full h-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
              {user.name ? user.name.charAt(0) : <UserIcon size={16} />}
          </div>
      );
  };

  // Theme Styles
  const bgClass = theme === 'light' ? 'bg-white border-slate-200 shadow-xl' : 'bg-[#0f172a] border-slate-800 shadow-2xl';
  const textClass = theme === 'light' ? 'text-slate-800' : 'text-white';
  const subTextClass = theme === 'light' ? 'text-slate-500' : 'text-slate-400';
  const hoverClass = theme === 'light' ? 'hover:bg-slate-100 hover:text-slate-900' : 'hover:bg-slate-800/80 hover:text-white';
  const activeClass = theme === 'light' ? 'bg-blue-50 text-blue-700 shadow-sm border border-blue-100' : 'bg-blue-600 text-white shadow-lg shadow-blue-900/20';

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-72'} ${bgClass} ${textClass} h-screen flex flex-col transition-all duration-300 ease-in-out border-r relative z-50`}>
      <button 
        onClick={onCollapse} 
        className={`absolute -right-3 top-10 rounded-full p-1.5 shadow-lg border-2 transition-all z-[60] ${theme === 'light' ? 'bg-white text-slate-600 border-slate-100 hover:text-blue-600' : 'bg-blue-600 text-white border-[#0f172a] hover:bg-blue-500'}`}
      >
        {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
      </button>

      <div className={`p-6 border-b ${theme === 'light' ? 'border-slate-100' : 'border-slate-800/80'} flex flex-col items-center ${isCollapsed ? 'justify-center' : 'items-start'}`}>
        <div className="flex items-center justify-between w-full">
            <div className="flex items-center gap-3.5">
                {logoUrl ? (
                    <img src={logoUrl} alt="Logo" className="w-9 h-9 object-contain drop-shadow-[0_0_15px_rgba(59,130,246,0.6)]" />
                ) : (
                    <div className="w-9 h-9 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/50">
                        <Database className="w-5 h-5 text-white" />
                    </div>
                )}
                {!isCollapsed && (
                    <div className="animate-in fade-in slide-in-from-left-2 duration-300">
                        <h1 className={`text-base font-black leading-none uppercase tracking-tighter mb-1 ${textClass}`}>
                            {systemName || 'GeoMaster'}
                        </h1>
                        <div className="flex items-center gap-1.5">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                            <p className={`text-[9px] font-bold tracking-[0.2em] uppercase ${subTextClass}`}>Enterprise</p>
                        </div>
                    </div>
                )}
            </div>

            {user && !isCollapsed && (
                <div className="relative" ref={notiRef}>
                    <button 
                        onClick={handleOpenNoti}
                        className={`p-2 rounded-xl transition-all ${isNotiOpen ? 'bg-blue-600 text-white' : `${theme === 'light' ? 'bg-slate-100 text-slate-500 hover:bg-slate-200' : 'bg-slate-800/50 text-slate-400 hover:bg-slate-800'}`}`}
                    >
                        <Bell size={18} />
                        {unreadCount > 0 && (
                            <span className={`absolute -top-1 -right-1 w-4 h-4 bg-red-600 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 animate-bounce ${theme === 'light' ? 'border-white' : 'border-[#0f172a]'}`}>
                                {unreadCount}
                            </span>
                        )}
                    </button>

                    {isNotiOpen && (
                        <div className={`absolute left-10 top-0 w-80 border rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 z-[100] ${theme === 'light' ? 'bg-white border-slate-200' : 'bg-slate-900 border-slate-700'}`}>
                            <div className={`p-4 border-b flex justify-between items-center ${theme === 'light' ? 'border-slate-100 bg-slate-50' : 'border-slate-800 bg-slate-950/50'}`}>
                                <h4 className={`text-[10px] font-black uppercase tracking-widest ${theme === 'light' ? 'text-slate-700' : 'text-white'}`}>Trung tâm Thông báo</h4>
                                <button onClick={() => setIsNotiOpen(false)} className={`${theme === 'light' ? 'text-slate-400 hover:text-slate-600' : 'text-slate-500 hover:text-white'}`}><X size={14}/></button>
                            </div>
                            <div className="max-h-96 overflow-y-auto custom-scrollbar">
                                {notifications.length === 0 ? (
                                    <div className={`p-10 text-center italic text-xs ${subTextClass}`}>Không có thông báo mới</div>
                                ) : notifications.map(n => (
                                    <div key={n.id} className={`p-4 border-b transition-colors ${theme === 'light' ? 'border-slate-100 hover:bg-slate-50' : 'border-slate-800/50 hover:bg-slate-800/30'}`}>
                                        <div className="flex gap-3">
                                            <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center ${
                                                n.type === 'DANGER' ? 'bg-red-900/30 text-red-500' :
                                                n.type === 'WARNING' ? 'bg-orange-900/30 text-orange-500' :
                                                'bg-blue-900/30 text-blue-500'
                                            }`}>
                                                {n.type === 'DANGER' ? <AlertTriangle size={14}/> : <Info size={14}/>}
                                            </div>
                                            <div className="flex-1 overflow-hidden">
                                                <p className={`text-xs font-black mb-1 ${theme === 'light' ? 'text-slate-800' : 'text-slate-200'}`}>{n.title}</p>
                                                <p className={`text-[10px] leading-relaxed mb-2 ${theme === 'light' ? 'text-slate-500' : 'text-slate-500'}`}>{n.content}</p>
                                                <div className={`flex items-center gap-2 text-[8px] font-bold uppercase ${theme === 'light' ? 'text-slate-400' : 'text-slate-600'}`}>
                                                    <Clock size={8}/> {new Date(n.created_at).toLocaleDateString()}
                                                    <span>•</span>
                                                    <span>Admin: {n.sender_name}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <div className="flex-1 py-6 space-y-1.5 overflow-y-auto custom-scrollbar no-scrollbar px-3">
        {loading ? (
            <div className="animate-pulse flex flex-col gap-3 px-2">
                {[1,2,3].map(i => <div key={i} className={`h-11 rounded-xl w-full ${theme === 'light' ? 'bg-slate-200' : 'bg-slate-800/50'}`}></div>)}
            </div>
        ) : visibleItems.map(item => {
          const isActive = activePage === item.id;
          let IconComponent = (Icons as any)[item.icon] || HelpCircle;

          let label = item.label;
          if (item.id === 'messaging') {
              label = 'Hộp thư nội bộ';
              IconComponent = Mail;
          }

          return (
            <button
              key={item.id}
              onClick={() => handleMenuClick(item)}
              title={isCollapsed ? label : ''}
              className={`w-full flex items-center gap-3.5 px-4 py-3 rounded-xl transition-all relative group overflow-hidden ${
                isActive ? activeClass : `${subTextClass} ${hoverClass}`
              }`}
            >
              <div className={`${isCollapsed ? 'mx-auto' : ''} transition-transform group-hover:scale-110 flex items-center z-10`}>
                <IconComponent size={20} className={isActive ? (theme === 'light' ? 'text-blue-700' : 'text-white') : (theme === 'light' ? 'text-slate-400 group-hover:text-slate-900' : 'text-slate-400 group-hover:text-blue-400')} />
              </div>

              {!isCollapsed && (
                <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-2 duration-300 z-10">
                    <span className={`font-bold text-xs uppercase tracking-wide ${isActive ? (theme === 'light' ? 'text-blue-900' : 'text-white') : ''}`}>
                        {label}
                    </span>
                    {item.type === 'EXTERNAL' && (
                        <ExternalLink size={12} className={`${subTextClass} group-hover:text-current transition-colors`} />
                    )}
                </div>
              )}
            </button>
          );
        })}
      </div>

      <div className={`p-4 border-t ${theme === 'light' ? 'border-slate-100 bg-slate-50/80' : 'border-slate-800/80 bg-slate-900/50'} backdrop-blur-sm`}>
        {user ? (
          <div className="flex flex-col gap-3">
            {/* THEME TOGGLE */}
            <button 
                onClick={onToggleTheme}
                className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all border ${
                    theme === 'light' 
                    ? 'bg-white border-slate-200 text-slate-600 hover:border-blue-400 hover:text-blue-600 shadow-sm' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700 hover:text-white'
                } ${isCollapsed ? 'justify-center' : ''}`}
                title="Chuyển giao diện Sáng/Tối"
            >
                {theme === 'light' ? <Sun size={18} className="text-orange-500" /> : <Moon size={18} className="text-blue-400" />}
                {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">{theme === 'light' ? 'Giao diện Sáng' : 'Giao diện Tối'}</span>}
            </button>

            {isCollapsed && (
                <button onClick={handleOpenNoti} className={`w-10 h-10 mx-auto rounded-full flex items-center justify-center transition-colors relative mb-2 ${theme === 'light' ? 'bg-slate-200 text-slate-500 hover:text-blue-600' : 'bg-slate-800 text-slate-400 hover:text-blue-400'}`}>
                    <Bell size={18}/>
                    {unreadCount > 0 && <span className={`absolute top-0 right-0 w-3 h-3 bg-red-600 rounded-full border-2 ${theme === 'light' ? 'border-white' : 'border-[#0f172a]'}`}></span>}
                </button>
            )}

            {!isCollapsed ? (
              <div 
                onClick={() => onNavigate('profile')}
                className={`flex items-center gap-3.5 p-2.5 rounded-xl cursor-pointer transition-all group border border-transparent ${theme === 'light' ? 'hover:bg-white hover:shadow-sm hover:border-slate-200' : 'hover:bg-slate-800 hover:border-slate-700/50'}`}
                title="Cập nhật hồ sơ"
              >
                  <div className={`w-10 h-10 rounded-full border-2 overflow-hidden shrink-0 shadow-lg transition-all ${theme === 'light' ? 'border-slate-200 group-hover:border-blue-400' : 'border-slate-700 group-hover:border-blue-500'}`}>
                    {renderAvatar()}
                  </div>
                  <div className="overflow-hidden flex-1">
                      <p className={`text-xs font-black truncate transition-colors ${theme === 'light' ? 'text-slate-800 group-hover:text-blue-600' : 'text-white group-hover:text-blue-400'}`}>
                          {user.name}
                      </p>
                      <p className={`text-[10px] font-bold uppercase tracking-wider mt-0.5 flex items-center gap-1 ${subTextClass}`}>
                          <span className={`w-1.5 h-1.5 rounded-full ${user.role === 'ADMIN' ? 'bg-orange-500' : 'bg-blue-500'}`}></span>
                          {user.role}
                      </p>
                  </div>
              </div>
            ) : (
                 <div 
                    onClick={() => onNavigate('profile')} 
                    className={`w-10 h-10 mx-auto rounded-full border-2 overflow-hidden cursor-pointer mb-3 shadow-lg transition-all ${theme === 'light' ? 'border-slate-200 hover:border-blue-400' : 'border-slate-700 hover:border-blue-500'}`}
                    title={user.name}
                 >
                    {renderAvatar()}
                 </div>
            )}

            <button 
              onClick={onLogout}
              title={isCollapsed ? "Đăng xuất" : ""}
              className={`flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all border ${theme === 'light' ? 'bg-red-50 text-red-500 border-red-100 hover:bg-red-100' : 'bg-red-500/10 text-red-400 border-red-500/10 hover:bg-red-500 hover:text-white'} ${isCollapsed ? 'justify-center' : ''}`}
            >
              <LogOut size={18} />
              {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng xuất</span>}
            </button>
          </div>
        ) : (
          <button 
            onClick={onLoginClick}
            className="w-full flex items-center gap-2 px-4 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all shadow-lg shadow-blue-900/30 group"
          >
            <LogIn size={18} className="group-hover:-translate-x-0.5 transition-transform" />
            {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng nhập</span>}
          </button>
        )}
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useEffect, useState, useRef } from 'react';
import { statsService } from '../services/mockBackend';
import { DashboardStats, User } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell, Sector } from 'recharts';
import { FileText, Download, RefreshCw, DollarSign, Scaling, Building, ChevronRight, Activity, Loader2 } from 'lucide-react';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const COLORS = ['#6366f1', '#06b6d4', '#10b981', '#f59e0b', '#ef4444', '#ec4899', '#8b5cf6', '#3b82f6', '#475569'];

const MOCK_FALLBACK: DashboardStats = {
    totalParcels: 12450,
    totalArea: 450200,
    totalValue: 21800000000,
    parcelsByType: [
        { name: 'Đất ở đô thị', value: 4500 },
        { name: 'Đất nông nghiệp', value: 3200 },
        { name: 'Đất trồng cây lâu năm', value: 2100 },
        { name: 'Đất sản xuất kinh doanh', value: 1500 },
        { name: 'Đất tôn giáo', value: 450 },
        { name: 'Đất công trình công cộng', value: 700 }
    ],
    valueByBranch: [
        { name: 'Phường Hiệp Thành', value: 2400 },
        { name: 'Phường Phú Lợi', value: 2100 },
        { name: 'Phường Phú Hòa', value: 1950 },
        { name: 'Phường Phú Mỹ', value: 1800 },
        { name: 'Phường Phú Cường', value: 1600 }
    ]
};

interface DashboardProps {
    user: User;
    theme?: 'dark' | 'light';
}

const renderActiveShape = (props: any) => {
  const { cx, cy, midAngle, innerRadius, outerRadius, startAngle, endAngle, fill, payload, percent, theme } = props;
  return (
    <g>
      <text x={cx} y={cy} dy={8} textAnchor="middle" fill={theme === 'light' ? '#1e293b' : '#fff'} className="font-display font-black text-lg uppercase tracking-tighter">
        {payload.name.length > 10 ? payload.name.substring(0, 10) + '...' : payload.name}
      </text>
      <Sector cx={cx} cy={cy} innerRadius={innerRadius} outerRadius={outerRadius + 10} startAngle={startAngle} endAngle={endAngle} fill={fill} />
      <Sector cx={cx} cy={cy} startAngle={startAngle} endAngle={endAngle} innerRadius={outerRadius + 14} outerRadius={outerRadius + 18} fill={fill} opacity={0.3} />
    </g>
  );
};

const Dashboard: React.FC<DashboardProps> = ({ user, theme = 'dark' }) => {
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [loading, setLoading] = useState(true);
  const [isExporting, setIsExporting] = useState<string | null>(null);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const dashboardRef = useRef<HTMLDivElement>(null);

  // Theme Constants
  const isLight = theme === 'light';
  const bgClass = isLight ? 'bg-white border-slate-200 shadow-lg text-slate-800' : 'bg-white/5 backdrop-blur-xl border-white/10 shadow-xl text-white';
  const textHeadClass = isLight ? 'text-slate-900' : 'text-white';
  const textSubClass = isLight ? 'text-slate-500' : 'text-gray-500';
  const buttonClass = isLight ? 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-blue-400 hover:text-blue-600' : 'bg-white/5 border border-white/10 hover:bg-emerald-600 text-white';

  const fetchStats = async () => {
    try {
        setLoading(true);
        const data = await statsService.getDashboardStats();
        if (!data || data.totalParcels === 0) {
            setStats(MOCK_FALLBACK);
        } else {
            setStats(data);
        }
        setLastUpdated(new Date());
    } catch (err: any) {
        setStats(MOCK_FALLBACK);
    } finally {
        setTimeout(() => setLoading(false), 500); 
    }
  };

  useEffect(() => {
    fetchStats();
    const interval = setInterval(fetchStats, 60000); 
    return () => clearInterval(interval);
  }, [user]);

  const handleExportExcel = () => {
    if (!stats) return;
    setIsExporting('EXCEL');
    setTimeout(() => {
        const rows = [
            ["BÁO CÁO THỐNG KÊ QUẢN LÝ ĐẤT ĐAI - GEOMASTER"],
            ["Chi nhánh", user.branchId || "Trụ sở chính"],
            ["Thời điểm xuất", new Date().toLocaleString("vi-VN")],
            [""],
            ["--- CHỈ SỐ TỔNG QUAN ---"],
            ["Chỉ tiêu", "Giá trị", "Đơn vị"],
            ["Tổng số thửa đất", stats.totalParcels, "Thửa"],
            ["Tổng diện tích", stats.totalArea.toFixed(2), "m2"],
            ["Giá trị tích lũy (tạm tính)", stats.totalValue, "VND"],
            [""],
            ["--- CƠ CẤU LOẠI ĐẤT ---"],
            ["Loại đất", "Số lượng thửa"],
            ...stats.parcelsByType.map(p => [p.name, p.value]),
            [""],
            ["--- MẬT ĐỘ THEO KHU VỰC ---"],
            ["Tên khu vực/phân khu", "Số lượng thửa"],
            ...stats.valueByBranch.map(v => [v.name, v.value])
        ];
        let csvContent = "\uFEFF"; 
        rows.forEach(rowArray => {
            const row = rowArray.map(val => {
                if (typeof val === 'string') return `"${val.replace(/"/g, '""')}"`;
                return val;
            }).join(",");
            csvContent += row + "\r\n";
        });
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `BaoCao_ThongKe_${new Date().getTime()}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        setIsExporting(null);
    }, 800);
  };

  const handleExportPDF = async () => {
    if (!dashboardRef.current) return;
    setIsExporting('PDF');
    const element = dashboardRef.current;
    try {
        const orbs = element.querySelectorAll('.decoration-layers');
        orbs.forEach(orb => (orb as HTMLElement).style.display = 'none');
        const canvas = await html2canvas(element, {
            scale: 2.5, 
            useCORS: true,
            backgroundColor: isLight ? '#f1f5f9' : '#0B0C10',
            logging: false,
            onclone: (clonedDoc) => {
                const clonedElement = clonedDoc.querySelector('.mesh-bg') as HTMLElement;
                if (clonedElement) {
                    clonedElement.style.filter = 'none';
                    clonedElement.style.backdropFilter = 'none';
                }
                const buttons = clonedDoc.querySelectorAll('button');
                buttons.forEach(btn => (btn as HTMLElement).style.display = 'none');
            }
        });
        orbs.forEach(orb => (orb as HTMLElement).style.display = 'block');
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('p', 'mm', 'a4');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight, undefined, 'FAST');
        pdf.save(`ThongKe_GeoMaster_${new Date().getTime()}.pdf`);
    } catch (error) {
        console.error("PDF Export Error:", error);
    } finally {
        setIsExporting(null);
    }
  };

  if (loading && !stats) return (
      <div className={`p-8 flex h-full items-center justify-center flex-col gap-4 ${isLight ? 'bg-slate-50' : 'bg-[#0B0C10] mesh-bg animate-mesh'}`}>
          <RefreshCw className="animate-spin w-10 h-10 text-cyan-500" />
          <p className={`font-display font-black uppercase tracking-[0.3em] text-[10px] ${isLight ? 'text-slate-500' : 'text-cyan-400'}`}>Đang truy xuất hệ thống...</p>
      </div>
  );

  const displayStats = stats || MOCK_FALLBACK;

  return (
    <div ref={dashboardRef} className={`relative p-6 min-h-full overflow-x-hidden overflow-y-auto h-full custom-scrollbar ${isLight ? 'bg-slate-100' : 'bg-[#0B0C10] mesh-bg animate-mesh'}`}>

      {/* BACKGROUND DECORATION (Only for Dark Mode or subtle for Light) */}
      {!isLight && (
          <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0 decoration-layers">
              <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full animate-orb-move"></div>
              <div className="absolute bottom-[0%] right-[-5%] w-[30%] h-[30%] bg-purple-600/10 blur-[100px] rounded-full animate-orb-move" style={{ animationDelay: '-8s' }}></div>
          </div>
      )}

      {/* HEADER SECTION */}
      <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4 animate-reveal-up">
        <div>
          <div className={`flex items-center gap-2 font-black text-[9px] uppercase tracking-[0.3em] mb-1 ${isLight ? 'text-blue-600' : 'text-cyan-400'}`}>
             <div className="w-1 h-1 rounded-full bg-cyan-500 shadow-[0_0_8px_#22d3ee] animate-pulse"></div>
             Khai thác dữ liệu thời gian thực
          </div>
          <h2 className={`text-3xl font-black tracking-tighter uppercase font-display bg-clip-text text-transparent ${isLight ? 'bg-gradient-to-r from-slate-900 to-slate-600' : 'bg-gradient-to-r from-white to-gray-400'}`}>
            Hệ thống Thống kê
          </h2>
          <div className="text-gray-500 text-[10px] flex items-center gap-2 mt-2 font-bold">
            <span className={`px-3 py-1 rounded-lg uppercase border ${isLight ? 'bg-white border-slate-200 text-slate-500' : 'bg-white/5 border-white/10 text-gray-400 backdrop-blur-md'}`}>
                SYNC: {lastUpdated.toLocaleTimeString()}
            </span>
            <ChevronRight size={12} className="text-blue-500" />
            <span className="font-black text-blue-400 uppercase tracking-widest">{user.branchId}</span>
          </div>
        </div>
        <div className="flex gap-2 export-buttons">
          <button 
            onClick={handleExportExcel}
            disabled={!!isExporting}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black transition-all shadow-xl active:scale-95 group disabled:opacity-50 ${buttonClass}`}
          >
            {isExporting === 'EXCEL' ? <Loader2 size={14} className="animate-spin" /> : <FileText size={14} />} EXCEL
          </button>
          <button 
            onClick={handleExportPDF}
            disabled={!!isExporting}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black transition-all shadow-xl active:scale-95 group disabled:opacity-50 ${isLight ? 'bg-white border border-slate-200 text-slate-600 hover:text-red-600 hover:border-red-200' : 'bg-white/5 border border-white/10 hover:bg-rose-600'}`}
          >
            {isExporting === 'PDF' ? <Loader2 size={14} className="animate-spin" /> : <Download size={14} />} PDF
          </button>
        </div>
      </div>

      {/* METRIC CARDS */}
      <div className="relative z-10 grid grid-cols-1 md:grid-cols-3 gap-5 mb-8">
        {[
          { label: 'QUY MÔ THỬA', value: displayStats.totalParcels.toLocaleString(), suffix: 'thửa', icon: Building, color: 'blue', delay: '0.1s' },
          { label: 'DIỆN TÍCH QUẢN LÝ', value: Math.round(displayStats.totalArea).toLocaleString(), suffix: 'm²', icon: Scaling, color: 'purple', delay: '0.2s' },
          { label: 'GIÁ TRỊ TÍCH LŨY', value: displayStats.totalValue > 1e9 ? `${(displayStats.totalValue / 1e9).toFixed(1)} TỶ` : `${(displayStats.totalValue / 1e6).toFixed(0)} TR`, suffix: 'VNĐ', icon: DollarSign, color: 'cyan', delay: '0.3s' }
        ].map((card, idx) => (
          <div key={idx} 
               style={{ animationDelay: card.delay }}
               className={`${bgClass} p-6 rounded-2xl relative overflow-hidden group transition-all duration-500 animate-reveal-up opacity-0`}>
              <div className={`absolute top-0 left-0 w-full h-0.5 bg-${card.color}-500 group-hover:h-1 transition-all`}></div>
              <div className="flex justify-between items-start mb-4">
                  <div className={`p-3 rounded-xl transition-all shadow-lg ${isLight ? `bg-${card.color}-50 text-${card.color}-600` : `bg-${card.color}-500/20 text-${card.color}-400`}`}>
                      <card.icon size={20} />
                  </div>
                  <Activity className={`text-${card.color}-500 opacity-20 group-hover:opacity-100 transition-opacity`} size={16} />
              </div>
              <h3 className={`${textSubClass} text-[9px] font-black uppercase tracking-[0.2em] mb-1`}>{card.label}</h3>
              <div className="flex items-end gap-1.5">
                <p className={`${textHeadClass} text-3xl font-black font-display tracking-tighter leading-none`}>{card.value}</p>
                <span className="text-gray-400 text-[9px] font-bold uppercase mb-0.5">{card.suffix}</span>
              </div>
          </div>
        ))}
      </div>

      <div className="relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-6 mb-12">
        {/* CHART 1: DOUGHNUT */}
        <div className={`${bgClass} p-6 rounded-3xl animate-reveal-left opacity-0`} style={{ animationDelay: '0.4s' }}>
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="text-lg font-black uppercase tracking-tighter text-blue-500 font-display">Cơ cấu loại đất</h3>
                    <p className={`${textSubClass} text-[9px] font-bold uppercase tracking-widest mt-1`}>Phân bổ chi tiết toàn vùng</p>
                </div>
                <div className={`p-2 rounded-xl cursor-pointer transition-all ${isLight ? 'bg-slate-50 text-slate-400 hover:text-slate-600' : 'bg-white/10 text-gray-400 hover:text-white'}`} onClick={fetchStats}>
                    <RefreshCw size={16} className={loading ? "animate-spin" : ""}/>
                </div>
            </div>
            <div className="h-[380px] relative">
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <defs>
                            {COLORS.map((color, i) => (
                                <linearGradient key={`pie-grad-${i}`} id={`pie-grad-${i}`} x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="0%" stopColor={color} stopOpacity={1}/>
                                    <stop offset="100%" stopColor={color} stopOpacity={0.6}/>
                                </linearGradient>
                            ))}
                        </defs>
                        <Pie
                            {...({
                                activeIndex: activeIndex !== null ? activeIndex : undefined,
                                activeShape: (props: any) => renderActiveShape({ ...props, theme }),
                            } as any)}
                            data={displayStats.parcelsByType}
                            cx="50%" cy="45%"
                            innerRadius={90} outerRadius={130}
                            paddingAngle={4}
                            dataKey="value" nameKey="name"
                            cornerRadius={10}
                            stroke={isLight ? "#fff" : "rgba(255,255,255,0.05)"} strokeWidth={4}
                            onMouseEnter={(_, index) => setActiveIndex(index)}
                            onMouseLeave={() => setActiveIndex(null)}
                        >
                            {displayStats.parcelsByType.map((_, index) => (
                                <Cell key={`cell-${index}`} fill={`url(#pie-grad-${index % COLORS.length})`} className="cursor-pointer hover:brightness-110 transition-all outline-none" />
                            ))}
                        </Pie>
                        <Tooltip 
                            contentStyle={{ 
