                            tickLine={false} 
                        />
                        <Tooltip 
                            cursor={{fill: isLight ? 'rgba(0,0,0,0.05)' : 'rgba(255,255,255,0.05)', radius: 8}} 
                            contentStyle={{ 
                                backgroundColor: isLight ? 'rgba(255, 255, 255, 0.95)' : 'rgba(11, 12, 16, 0.95)', 
                                border: isLight ? '1px solid #e2e8f0' : '1px solid rgba(255,255,255,0.1)', 
                                borderRadius: '12px',
                                color: isLight ? '#0f172a' : '#fff'
                            }}
                        />
                        <Bar 
                            dataKey="value" 
                            fill="url(#barGradient)" 
                            radius={[0, 10, 10, 0]} 
                            barSize={18} 
                            animationDuration={1500}
                            label={{ 
                                position: 'right', 
                                fill: isLight ? '#64748b' : '#94a3b8',
                                fontSize: 10, 
                                fontWeight: '900', 
                                offset: 12,
                                formatter: (val: number) => val.toLocaleString()
                            }}
                        />
                    </BarChart>
                </ResponsiveContainer>
            </div>
        </div>
      </div>
    </div>
  );
};

