                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1 tracking-widest">Ghi chú mô tả</label>
                                        <textarea className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white text-xs h-20 resize-none outline-none focus:border-blue-500 shadow-inner" value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})} placeholder="Nhập mô tả về bảng dữ liệu..."/>
                                    </div>
                                </>
                            )}

                            {modalType === 'BASEMAP' && (
                                <>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên bản đồ nền</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-bold" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="VD: Vệ tinh Google"/>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Loại chuẩn</label>
                                        <select className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none" value={formData.type || 'XYZ'} onChange={e => setFormData({...formData, type: e.target.value})}>
                                            <option value="XYZ">XYZ Tiles</option>
                                            <option value="OSM">OpenStreetMap (Free)</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">URL (Template {`{z}/{x}/{y}`})</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white font-mono text-xs" value={formData.url || ''} onChange={e => setFormData({...formData, url: e.target.value})} disabled={formData.type === 'OSM'} placeholder="https://mt1.google.com/vt/lyrs=s&x={x}&y={y}&z={z}"/>
                                    </div>
                                    <div className="flex gap-4 p-2 bg-gray-900/30 rounded-lg border border-gray-700">
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <div className={`w-5 h-5 rounded border border-gray-600 flex items-center justify-center ${formData.isDefault ? 'bg-orange-600 border-orange-600' : 'bg-gray-800'}`} onClick={() => setFormData({...formData, isDefault: !formData.isDefault})}>
                                                {formData.isDefault && <Check size={14} className="text-white"/>}
                                            </div>
                                            <span className="text-xs text-gray-300 font-bold uppercase tracking-tighter">Mặc định</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <div className={`w-5 h-5 rounded border border-gray-600 flex items-center justify-center ${formData.visible ? 'bg-green-600 border-green-600' : 'bg-gray-800'}`} onClick={() => setFormData({...formData, visible: !formData.visible})}>
                                                {formData.visible && <Check size={14} className="text-white"/>}
                                            </div>
                                            <span className="text-xs text-gray-300 font-bold uppercase tracking-tighter">Hiện Menu</span>
                                        </label>
                                    </div>
                                </>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-gray-700">
                            <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-400 hover:text-white font-bold text-sm uppercase transition-colors">Hủy</button>
                            <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-2 rounded-lg font-black text-sm shadow-lg flex items-center gap-2 active:scale-95 disabled:opacity-50 transition-all uppercase tracking-widest">
                                {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>}
                                {isEditMode ? "LƯU THAY ĐỔI" : "XÁC NHẬN THÊM"}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* CONFIRMATION MODAL */}
            {confirmDialog.isOpen && (
                <div className="fixed inset-0 z-[600] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-sm border border-gray-700 shadow-2xl overflow-hidden">
                        <div className={`p-6 flex flex-col items-center text-center ${confirmDialog.isDangerous ? 'bg-red-950/20' : 'bg-orange-950/20'}`}>
                            <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${confirmDialog.isDangerous ? 'bg-red-500 text-white' : 'bg-orange-500 text-white'}`}>
                                <ShieldAlert size={32} />
                            </div>
                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{confirmDialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed">{confirmDialog.message}</p>
                        </div>
                        <div className="p-4 bg-gray-900/50 flex gap-3">
                            <button onClick={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} className="flex-1 py-3 text-sm font-bold text-gray-400 hover:text-white uppercase">Hủy bỏ</button>
                            <button onClick={executeAction} className={`flex-1 py-3 text-sm font-black rounded-xl uppercase shadow-lg ${confirmDialog.isDangerous ? 'bg-red-600 hover:bg-red-500 text-white' : 'bg-blue-600 hover:bg-blue-500 text-white'}`}>Xác nhận</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default LayerManager;
